  output logic                       cmd_arb_mop_o,
  output logic                       cmd_arb_eop_o,
  input logic                        cmd_arb_gnt_i,
  output logic [CmdBusWidth-1:0]     cmd_arb_bus_o,
  
  input logic                        cmd_ack_i,
  input csrng_cmd_sts_e              cmd_ack_sts_i,
  
  output logic                       cmd_stage_ack_o,
  output csrng_cmd_sts_e             cmd_stage_ack_sts_o,
  
  input logic                        genbits_vld_i,
  input logic [127:0]                genbits_bus_i,
  input logic                        genbits_fips_i,
  
  output logic                       genbits_vld_o,
  input logic                        genbits_rdy_i,
  output logic [127:0]               genbits_bus_o,
  output logic                       genbits_fips_o,
  
  output logic [2:0]                 cmd_stage_sfifo_cmd_err_o,
  output logic [2:0]                 cmd_stage_sfifo_genbits_err_o,
  output logic                       cmd_gen_cnt_err_o,
  output logic                       cmd_stage_sm_err_o
);
  
  localparam int GenBitsFifoWidth = 1 + BlkLen;
  localparam int GenBitsFifoDepth = 1;
  
  logic      [CmdBusWidth-1:0] sfifo_cmd_rdata;
  logic     [CmdFifoDepthLg:0] sfifo_cmd_depth;
  logic                        sfifo_cmd_wvld;
  logic                        sfifo_cmd_wrdy;
  logic      [CmdBusWidth-1:0] sfifo_cmd_wdata;
  logic                        sfifo_cmd_rrdy;
  logic                  [2:0] sfifo_cmd_err;
  logic                        sfifo_cmd_rvld;
  
  logic [GenBitsFifoWidth-1:0] sfifo_genbits_rdata;
  logic                        sfifo_genbits_wvld;
  logic                        sfifo_genbits_wrdy;
  logic [GenBitsFifoWidth-1:0] sfifo_genbits_wdata;
  logic                        sfifo_genbits_rrdy;
  logic                  [2:0] sfifo_genbits_err;
  logic                        sfifo_genbits_rvld;
  
  logic                  [3:0] cmd_len;
  logic                        cmd_fifo_zero;
  logic                        cmd_fifo_pop;
  logic                        cmd_len_dec;
  logic                        cmd_gen_cnt_dec;
  logic                        cmd_gen_1st_req;
  logic                        cmd_gen_inc_req;
  logic                        cmd_gen_cnt_last;
  logic                        cmd_final_ack;
  logic                        cmd_err_ack;
  logic  [GenBitsCtrWidth-1:0] cmd_gen_cnt;
  csrng_cmd_sts_e              err_sts;
  logic                        reseed_cnt_exceeded;
  logic                        invalid_cmd_seq;
  logic                        invalid_acmd;
  logic                  [2:0] acmd;
  logic                        local_escalate;
  
  logic           cmd_ack_q, cmd_ack_d;
  csrng_cmd_sts_e cmd_ack_sts_q, cmd_ack_sts_d;
  logic     [3:0] cmd_len_q, cmd_len_d;
  logic           cmd_gen_flag_q, cmd_gen_flag_d;
  logic    [11:0] cmd_gen_cmd_q, cmd_gen_cmd_d;
  logic           instantiated_d, instantiated_q;
  always_ff @(posedge clk_i or negedge rst_ni) begin
    if (!rst_ni) begin
      cmd_ack_q       <= '0;
      cmd_ack_sts_q   <= CMD_STS_SUCCESS;
      cmd_len_q       <= '0;
      cmd_gen_flag_q  <= '0;
      cmd_gen_cmd_q   <= '0;
      instantiated_q  <= '0;
    end else begin
      cmd_ack_q       <= cmd_ack_d;
      cmd_ack_sts_q   <= cmd_ack_sts_d;
      cmd_len_q       <= cmd_len_d;
      cmd_gen_flag_q  <= cmd_gen_flag_d;
      cmd_gen_cmd_q   <= cmd_gen_cmd_d;
      instantiated_q  <= instantiated_d;
    end
  end
  assign cmd_stage_sfifo_cmd_err_o = sfifo_cmd_err;
  assign cmd_stage_sfifo_genbits_err_o = sfifo_genbits_err;
  
  
  
  prim_fifo_sync #(
    .Width(CmdBusWidth),
    .Pass(0),
    .Depth(CmdFifoDepth),
    .OutputZeroIfEmpty(1'b0)
  ) u_prim_fifo_cmd (
    .clk_i   (clk_i),
    .rst_ni  (rst_ni),
    .clr_i   (!cs_enable_i),
    .wvalid_i(sfifo_cmd_wvld),
    .wready_o(sfifo_cmd_wrdy),
    .wdata_i (sfifo_cmd_wdata),
    .rvalid_o(sfifo_cmd_rvld),
    .rready_i(sfifo_cmd_rrdy),
    .rdata_o (sfifo_cmd_rdata),
    .full_o  (),
    .depth_o (sfifo_cmd_depth),
    .err_o   ()
  );
  assign sfifo_cmd_wdata = cmd_stage_bus_i;
  assign sfifo_cmd_wvld = cs_enable_i && cmd_stage_rdy_o && cmd_stage_vld_i;
  assign sfifo_cmd_rrdy = cs_enable_i && cmd_fifo_pop;
  assign cmd_arb_bus_o =
         cmd_gen_inc_req ? {15'b0,cmd_gen_cnt_last,cmd_stage_shid_i,cmd_gen_cmd_q} :
        
        cmd_gen_1st_req ? {15'b0,cmd_gen_cnt_last,cmd_stage_shid_i,sfifo_cmd_rdata[11:0]} :
        cmd_arb_mop_o   ? sfifo_cmd_rdata :
        '0;
  assign cmd_stage_rdy_o = sfifo_cmd_wrdy;
  assign sfifo_cmd_err =
         {( sfifo_cmd_wvld && !sfifo_cmd_wrdy),
          ( sfifo_cmd_rrdy && !sfifo_cmd_rvld),
          (!sfifo_cmd_wrdy && !sfifo_cmd_rvld)};
  
  assign cmd_fifo_zero = (sfifo_cmd_depth == '0);
  assign cmd_len = sfifo_cmd_rdata[7:4];
  
  assign cmd_len_d =
         (!cs_enable_i) ? '0 :
         cmd_arb_sop_o ? cmd_len :
         cmd_len_dec ? (cmd_len_q-1) :
         cmd_len_q;
  
  assign acmd = sfifo_cmd_rdata[2:0];
  
  assign cmd_gen_flag_d =
         (!cs_enable_i) ? '0 :
         cmd_gen_1st_req ? (acmd == GEN) :
         cmd_gen_flag_q;
  assign cmd_gen_cmd_d =
         (!cs_enable_i) ? '0 :
         cmd_gen_1st_req ? {sfifo_cmd_rdata[11:0]} :
         cmd_gen_cmd_q;
  
  prim_count #(
    .Width(GenBitsCtrWidth),
    .ResetValue({GenBitsCtrWidth{1'b1}})
  ) u_prim_count_cmd_gen_cntr (
    .clk_i,
    .rst_ni,
    .clr_i(!cs_enable_i),
    .set_i(cmd_gen_1st_req),
    .set_cnt_i(sfifo_cmd_rdata[12 +: GenBitsCtrWidth]),
    .incr_en_i(1'b0),
    .decr_en_i(cmd_gen_cnt_dec), 
    .step_i(GenBitsCtrWidth'(1)),
    .commit_i(1'b1),
    .cnt_o(cmd_gen_cnt),
    .cnt_after_commit_o(),
    .err_o(cmd_gen_cnt_err_o)
  );
  
  assign local_escalate = cmd_gen_cnt_err_o;
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  localparam int StateWidth = 8;
  typedef enum logic [StateWidth-1:0] {
    Idle      = 8'b11110101, 
    Flush     = 8'b01011011, 
    ArbGnt    = 8'b00011100, 
    SendSOP   = 8'b00000001, 
    SendMOP   = 8'b01010110, 
    GenCmdChk = 8'b10001101, 
    CmdAck    = 8'b11000000, 
    GenReq    = 8'b10010011, 
    GenArbGnt = 8'b11101110, 
    GenSOP    = 8'b10111010, 
    Error     = 8'b01100111  
  } state_e;
  
  state_e state_d, state_q;
  `PRIM_FLOP_SPARSE_FSM(u_state_regs, state_d, state_q, state_e, Idle)
  always_comb begin
    state_d = state_q;
    cmd_fifo_pop = 1'b0;
    cmd_len_dec = 1'b0;
    cmd_gen_cnt_dec = 1'b0;
    cmd_gen_1st_req = 1'b0;
    cmd_gen_inc_req = 1'b0;
    cmd_gen_cnt_last = 1'b0;
    cmd_final_ack = 1'b0;
    cmd_arb_req_o = 1'b0;
    cmd_arb_sop_o = 1'b0;
    cmd_arb_mop_o = 1'b0;
    cmd_arb_eop_o = 1'b0;
    cmd_stage_sm_err_o = 1'b0;
    cmd_err_ack = 1'b0;
    reseed_cnt_exceeded = 1'b0;
    invalid_cmd_seq = 1'b0;
    invalid_acmd = 1'b0;
    instantiated_d = instantiated_q;
    if (state_q == Error) begin
      
      cmd_stage_sm_err_o = 1'b1;
    end else if (local_escalate) begin
      
      state_d = Error;
    end else if (!cs_enable_i && state_q inside {Idle, Flush, ArbGnt, SendSOP, SendMOP, GenCmdChk,
                                                 CmdAck, GenReq, GenArbGnt, GenSOP}) begin
      
      state_d = Idle;
      instantiated_d = 1'b0;
    end else begin
      
      unique case (state_q)
        Idle: begin
          
          if (!cmd_fifo_zero) begin
            if (acmd == INS) begin
              if (!instantiated_q) begin
                state_d = ArbGnt;
                instantiated_d = 1'b1;
              end
              if (instantiated_q) begin
                cmd_err_ack = 1'b1;
                invalid_cmd_seq = 1'b1;
                state_d = Idle;
              end
            end else if (acmd == RES) begin
              if (instantiated_q) begin
                state_d = ArbGnt;
              end
              if (!instantiated_q) begin
                cmd_err_ack = 1'b1;
                invalid_cmd_seq = 1'b1;
                state_d = Idle;
              end
            end else if (acmd == GEN) begin
              if (instantiated_q) begin
                
                
                if ((acmd == GEN) && reseed_cnt_reached_i) begin
                  cmd_err_ack = 1'b1;
                  reseed_cnt_exceeded = 1'b1;
                  state_d = Idle;
                end else begin
                  state_d = ArbGnt;
                end
              end
              if (!instantiated_q) begin
                cmd_err_ack = 1'b1;
                invalid_cmd_seq = 1'b1;
                state_d = Idle;
              end
            end else if (acmd == UPD) begin
              if (instantiated_q) begin
                state_d = ArbGnt;
              end
              if (!instantiated_q) begin
                cmd_err_ack = 1'b1;
                invalid_cmd_seq = 1'b1;
                state_d = Idle;
              end
            end else if (acmd == UNI) begin
              
              instantiated_d = 1'b0;
              state_d = ArbGnt;
            end else begin
              
              cmd_err_ack = 1'b1;
              invalid_acmd = 1'b1;
              state_d = Idle;
            end
            
            
            if (cmd_err_ack) begin
              cmd_fifo_pop = 1'b1;
              state_d = Flush;
            end
          end
        end
        Flush: begin
          
          
          
          
          cmd_fifo_pop = sfifo_cmd_rvld;
          if (!sfifo_cmd_rvld && !cmd_stage_vld_i) begin
            state_d = Idle;
          end
        end
        ArbGnt: begin
          cmd_arb_req_o = 1'b1;
          if (cmd_arb_gnt_i) begin
            state_d = SendSOP;
          end
        end
        SendSOP: begin
          cmd_gen_1st_req = 1'b1;
          cmd_arb_sop_o = 1'b1;
          cmd_fifo_pop = 1'b1;
          if (sfifo_cmd_rdata[12 +: GenBitsCtrWidth] == GenBitsCtrWidth'(1)) begin
            cmd_gen_cnt_last = 1'b1;
          end
          if (cmd_len == '0) begin
            cmd_arb_eop_o = 1'b1;
            state_d = GenCmdChk;
          end else begin
            state_d = SendMOP;
          end
        end
        SendMOP: begin
          if (!cmd_fifo_zero) begin
            cmd_fifo_pop = 1'b1;
            cmd_len_dec = 1'b1;
            if (cmd_len_q == 4'h1) begin
              cmd_arb_mop_o = 1'b1;
              cmd_arb_eop_o = 1'b1;
              state_d = GenCmdChk;
            end else begin
              cmd_arb_mop_o = 1'b1;
            end
          end
        end
        GenCmdChk: begin
          if (cmd_gen_flag_q) begin
            cmd_gen_cnt_dec = 1'b1;
          end
          state_d = CmdAck;
        end
        CmdAck: begin
          if (cmd_ack_i) begin
            
            
            
            state_d = GenReq;
          end
        end
        GenReq: begin
          
          if (cmd_gen_flag_q) begin
            
            if (sfifo_genbits_wrdy) begin
              if (cmd_gen_cnt == '0) begin
                cmd_final_ack = 1'b1;
                state_d = Idle;
              end else begin
                
                state_d = GenArbGnt;
              end
            end
          end else begin
            
            cmd_final_ack = 1'b1;
            state_d = Idle;
          end
        end
        GenArbGnt: begin
          cmd_arb_req_o = 1'b1;
          if (cmd_arb_gnt_i) begin
            state_d = GenSOP;
          end
        end
        GenSOP: begin
          cmd_arb_sop_o = 1'b1;
          cmd_arb_eop_o = 1'b1;
          cmd_gen_inc_req = 1'b1;
          state_d = GenCmdChk;
          
          if (cmd_gen_cnt == GenBitsCtrWidth'(1)) begin
            cmd_gen_cnt_last = 1'b1;
          end
        end
        
        default: begin
          state_d = Error;
          cmd_stage_sm_err_o = 1'b1;
        end
      endcase 
    end
  end
  
  
  
  prim_fifo_sync #(
    .Width(GenBitsFifoWidth),
    .Pass(0),
    .Depth(GenBitsFifoDepth),
    .OutputZeroIfEmpty(0) 
  ) u_prim_fifo_genbits (
    .clk_i   (clk_i),
    .rst_ni  (rst_ni),
    .clr_i   (!cs_enable_i),
    .wvalid_i(sfifo_genbits_wvld),
    .wready_o(sfifo_genbits_wrdy),
    .wdata_i (sfifo_genbits_wdata),
    .rvalid_o(sfifo_genbits_rvld),
    .rready_i(sfifo_genbits_rrdy),
    .rdata_o (sfifo_genbits_rdata),
    .full_o  (),
    .depth_o (), 
    .err_o   ()
  );
  assign sfifo_genbits_wdata = {genbits_fips_i,genbits_bus_i};
  
  
  
  
  
  
  
  
  
  
  
  assign sfifo_genbits_wvld = cs_enable_i && genbits_vld_i;
  assign sfifo_genbits_rrdy = genbits_vld_o && genbits_rdy_i;
  assign genbits_vld_o = cs_enable_i && sfifo_genbits_rvld;
  assign {genbits_fips_o, genbits_bus_o} = sfifo_genbits_rdata;
  assign sfifo_genbits_err =
         {( sfifo_genbits_wvld && !sfifo_genbits_wrdy),
          ( sfifo_genbits_rrdy && !sfifo_genbits_rvld),
          (!sfifo_genbits_wrdy && !sfifo_genbits_rvld)};
  
  `ASSERT(CsrngCmdStageGenbitsFifoFull_A, state_q == GenSOP |-> sfifo_genbits_wrdy)
  
  
  `ASSERT(CsrngCmdStageGenbitsFifoPushExpected_A,
      sfifo_genbits_wvld |-> state_q inside {GenCmdChk, CmdAck} && cmd_gen_flag_q)
  
  
  
  assign cmd_ack_d =
         (!cs_enable_i) ? '0 :
         cmd_final_ack || cmd_err_ack;
  assign cmd_stage_ack_o = cmd_ack_q;
  assign err_sts = reseed_cnt_exceeded ? CMD_STS_RESEED_CNT_EXCEEDED :
                   invalid_cmd_seq     ? CMD_STS_INVALID_CMD_SEQ     :
                   invalid_acmd        ? CMD_STS_INVALID_ACMD        : CMD_STS_INVALID_ACMD;
  assign cmd_ack_sts_d =
         (!cs_enable_i) ? CMD_STS_SUCCESS :
         cmd_err_ack ? err_sts :
         cmd_final_ack ? cmd_ack_sts_i :
         cmd_ack_sts_q;
  assign cmd_stage_ack_sts_o = cmd_ack_sts_q;
  assign reseed_cnt_alert_o = reseed_cnt_exceeded;
  assign invalid_cmd_seq_alert_o = invalid_cmd_seq;
  assign invalid_acmd_alert_o = invalid_acmd;
  
  
  `ASSERT(CsrngCmdStageErrorStStable_A, state_q == Error |=> $stable(state_q))
  
  `ASSERT(CsrngCmdStageErrorOutput_A,   state_q == Error |-> cmd_stage_sm_err_o)
endmodule

module csrng_core import csrng_pkg::*; #(
  parameter aes_pkg::sbox_impl_e SBoxImpl = aes_pkg::SBoxImplLut,
  parameter int NumHwApps = 2,
  parameter cs_keymgr_div_t RndCnstCsKeymgrDivNonProduction = CsKeymgrDivWidth'(0),
  parameter cs_keymgr_div_t RndCnstCsKeymgrDivProduction = CsKeymgrDivWidth'(0)
) (
  input logic                                     clk_i,
  input logic                                     rst_ni,
  input  csrng_reg_pkg::csrng_reg2hw_t            reg2hw,
  output csrng_reg_pkg::csrng_hw2reg_t            hw2reg,
  
  input  prim_mubi_pkg::mubi8_t                   otp_en_csrng_sw_app_read_i,
  
  input  lc_ctrl_pkg::lc_tx_t                     lc_hw_debug_en_i,
  
  output entropy_src_pkg::entropy_src_hw_if_req_t entropy_src_hw_if_o,
  input  entropy_src_pkg::entropy_src_hw_if_rsp_t entropy_src_hw_if_i,
  
  input  csrng_req_t [NumHwApps-1:0]              csrng_cmd_i,
  output csrng_rsp_t [NumHwApps-1:0]              csrng_cmd_o,
  
  output logic                                    recov_alert_test_o,
  output logic                                    fatal_alert_test_o,
  output logic                                    recov_alert_o,
  output logic                                    fatal_alert_o,
  
  output logic                                    intr_cs_cmd_req_done_o,
  output logic                                    intr_cs_entropy_req_o,
  output logic                                    intr_cs_hw_inst_exc_o,
  output logic                                    intr_cs_fatal_err_o
);
  import csrng_reg_pkg::*;
  import prim_mubi_pkg::mubi4_t;
  import prim_mubi_pkg::mubi4_test_true_strict;
  import prim_mubi_pkg::mubi4_test_invalid;
  localparam int unsigned ADataDepthClog = $clog2(CmdMaxClen) + 1;
  localparam int unsigned CsEnableCopies = 51;
  localparam int unsigned LcHwDebugCopies = 1;
  localparam int unsigned Flag0Copies = 3;
  
  
  logic                        event_cs_fatal_err;
  logic [CsEnableCopies-1:1]   cs_enable_fo;
  logic [Flag0Copies-1:0]      flag0_fo;
  logic                        acmd_flag0_pfa;
  logic                        cs_enable_pfa;
  logic                        sw_app_enable;
  logic                        sw_app_enable_pfe;
  logic                        sw_app_enable_pfa;
  logic                        read_int_state;
  logic                        read_int_state_pfe;
  logic                        read_int_state_pfa;
  logic                        fips_force_enable;
  logic                        fips_force_enable_pfe;
  logic                        fips_force_enable_pfa;
  logic                        recov_alert_event;
  logic                        acmd_avail;
  logic                        acmd_sop;
  logic                        acmd_mop;
  logic                        acmd_eop;
  logic                        state_db_wr_vld;
  csrng_state_t                state_db_rd_data;
  logic [CmdBusWidth-1:0]      acmd_bus;
  acmd_e                       acmd_hold;
  logic [SeedLen-1:0]          packer_adata;
  logic [ADataDepthClog-1:0]   packer_adata_depth;
  logic                        packer_adata_pop;
  logic                        packer_adata_clr;
  logic [SeedLen-1:0]          seed_diversification;
  logic                        cmd_entropy_req;
  logic                        cmd_entropy_avail;
  logic                        ctr_drbg_req_vld;
  logic                        ctr_drbg_req_rdy;
  csrng_core_data_t            ctr_drbg_req_data;
  logic                        ctr_drbg_rsp_vld;
  csrng_core_data_t            ctr_drbg_rsp_data;
  csrng_cmd_sts_e              ctr_drbg_rsp_sts;
  logic                        ctr_drbg_bits_vld;
  logic [BlkLen-1:0]           ctr_drbg_bits_data;
  logic                        ctr_drbg_bits_fips;
  logic                        acmd_accept;
  logic                        main_sm_cmd_vld;
  logic                        clr_adata_packer;
  logic                        fifo_write_err_sum;
  logic                        fifo_read_err_sum;
  logic                        fifo_status_err_sum;
  logic                        ctr_err_sum;
  logic                        cmd_stage_sm_err_sum;
  logic                        main_sm_err_sum;
  logic                        cs_main_sm_err;
  logic [MainSmStateWidth-1:0] cs_main_sm_state;
  logic                        ctr_drbg_sm_err_sum;
  logic                        ctr_drbg_sm_err;
  logic                        ctr_drbg_v_ctr_err;
  logic                        block_encrypt_sm_err_sum;
  logic                        block_encrypt_sm_err;
  
  logic                        block_encrypt_req_vld;
  logic                        block_encrypt_req_rdy;
  csrng_key_v_t                block_encrypt_req_data;
  logic                        block_encrypt_rsp_vld;
  logic                        block_encrypt_rsp_rdy;
  logic           [BlkLen-1:0] block_encrypt_rsp_data;
  logic [2:0]                  cmd_stage_sfifo_cmd_err[NumApps];
  logic [NumApps-1:0]          cmd_stage_sfifo_cmd_err_sum;
  logic [NumApps-1:0]          cmd_stage_sfifo_cmd_err_wr;
  logic [NumApps-1:0]          cmd_stage_sfifo_cmd_err_rd;
  logic [NumApps-1:0]          cmd_stage_sfifo_cmd_err_st;
  logic [2:0]                  cmd_stage_sfifo_genbits_err[NumApps];
  logic [NumApps-1:0]          cmd_stage_sfifo_genbits_err_sum;
  logic [NumApps-1:0]          cmd_stage_sfifo_genbits_err_wr;
  logic [NumApps-1:0]          cmd_stage_sfifo_genbits_err_rd;
  logic [NumApps-1:0]          cmd_stage_sfifo_genbits_err_st;
  logic [NumApps-1:0]          cmd_stage_ctr_err;
  logic [NumApps-1:0]          cmd_stage_sm_err;
  logic [NumApps-1:0]          cmd_stage_vld;
  logic [InstIdWidth-1:0]      cmd_stage_shid[NumApps];
  logic [CmdBusWidth-1:0]      cmd_stage_bus[NumApps];
  logic [NumApps-1:0]          cmd_stage_rdy;
  logic [NumApps-1:0]          cmd_arb_req;
  logic [NumApps-1:0]          cmd_arb_gnt;
  logic [$clog2(NumApps)-1:0]  cmd_arb_idx;
  logic [NumApps-1:0]          cmd_arb_sop;
  logic [NumApps-1:0]          cmd_arb_mop;
  logic [NumApps-1:0]          cmd_arb_eop;
  logic [CmdBusWidth-1:0]      cmd_arb_bus[NumApps];
  logic [NumApps-1:0]          cmd_core_ack;
  csrng_cmd_sts_e [NumApps-1:0]cmd_core_ack_sts;
  logic [NumApps-1:0]          cmd_stage_ack;
  csrng_cmd_sts_e [NumApps-1:0]cmd_stage_ack_sts;
  logic [NumApps-1:0]          genbits_core_vld;
  logic [BlkLen-1:0]           genbits_core_bus[NumApps];
  logic [NumApps-1:0]          genbits_core_fips;
  logic [NumApps-1:0]          genbits_stage_vld;
  logic [NumApps-1:0]          genbits_stage_fips;
  logic [BlkLen-1:0]           genbits_stage_bus[NumApps];
  logic [NumApps-1:0]          genbits_stage_rdy;
  logic                        genbits_stage_vld_sw;
  logic                        genbits_stage_bus_rd_sw;
  logic [31:0]                 genbits_stage_bus_sw;
  logic [15:0]                 hw_exception_sts;
  logic [LcHwDebugCopies-1:0]  lc_hw_debug_on_fo;
  logic                        state_db_reg_read_en;
  logic [30:0]                 err_code_test_bit;
  logic                        cs_rdata_capt_vld;
  logic                        cs_bus_cmp_alert;
  logic [NumApps-1:0]          invalid_cmd_seq_alert;
  logic [NumApps-1:0]          invalid_acmd_alert;
  logic [NumApps-1:0]          reseed_cnt_alert;
  logic [1:0]                  otp_sw_app_read_en;
  logic [NumApps-1:0][31:0]    reseed_counter;
  prim_mubi_pkg::mubi8_t                [1:0] otp_sw_app_read_en_mubi;
  prim_mubi_pkg::mubi4_t [CsEnableCopies-1:0] mubi_cs_enable_fanout;
  prim_mubi_pkg::mubi4_t    [Flag0Copies-1:0] mubi_flag0_fanout;
  
  acmd_e                  acmd_q, acmd_d;
  logic   [NumAppsLg-1:0] inst_id_q, inst_id_d;
  logic                   gen_last_q, gen_last_d;
  mubi4_t                 flag0_q, flag0_d;
  logic   [NumAppsLg-1:0] cmd_arb_idx_q, cmd_arb_idx_d;
  logic                   genbits_stage_fips_sw_q, genbits_stage_fips_sw_d;
  acmd_e                  ctr_drbg_cmd_q, ctr_drbg_cmd_d;
  logic     [SeedLen-1:0] entropy_src_seed_q, entropy_src_seed_d;
  logic                   entropy_src_fips_q, entropy_src_fips_d;
  logic            [63:0] cs_rdata_capt_q, cs_rdata_capt_d;
  logic                   cs_rdata_capt_vld_q, cs_rdata_capt_vld_d;
  logic                   sw_rdy_sts_q, sw_rdy_sts_d;
  logic                   sw_sts_ack_q, sw_sts_ack_d;
  logic     [NumApps-1:0] reseed_cnt_reached_q, reseed_cnt_reached_d;
  always_ff @(posedge clk_i or negedge rst_ni) begin
    if (!rst_ni) begin
      acmd_q                  <= INV;
      inst_id_q               <= '0;
      gen_last_q              <= '0;
      flag0_q                 <= prim_mubi_pkg::MuBi4False;
      cmd_arb_idx_q           <= '0;
      genbits_stage_fips_sw_q <= '0;
      ctr_drbg_cmd_q          <= INV;
      entropy_src_seed_q      <= '0;
      entropy_src_fips_q      <= '0;
      cs_rdata_capt_q         <= '0;
      cs_rdata_capt_vld_q     <= '0;
      sw_rdy_sts_q            <= '0;
      sw_sts_ack_q            <= '0;
      reseed_cnt_reached_q    <= '0;
    end else begin
      acmd_q                  <= acmd_d;
      inst_id_q               <= inst_id_d;
      gen_last_q              <= gen_last_d;
      flag0_q                 <= flag0_d;
      cmd_arb_idx_q           <= cmd_arb_idx_d;
      genbits_stage_fips_sw_q <= genbits_stage_fips_sw_d;
      ctr_drbg_cmd_q          <= ctr_drbg_cmd_d;
      entropy_src_seed_q      <= entropy_src_seed_d;
      entropy_src_fips_q      <= entropy_src_fips_d;
      cs_rdata_capt_q         <= cs_rdata_capt_d;
      cs_rdata_capt_vld_q     <= cs_rdata_capt_vld_d;
      sw_rdy_sts_q            <= sw_rdy_sts_d;
      sw_sts_ack_q            <= sw_sts_ack_d;
      reseed_cnt_reached_q    <= reseed_cnt_reached_d;
    end
  end
  
  
  
  
  prim_intr_hw #(
    .Width(1)
  ) u_intr_hw_cs_cmd_req_done (
    .clk_i                 (clk_i),
    .rst_ni                (rst_ni),
    .event_intr_i          (cmd_stage_ack[NumApps-1]),
    .reg2hw_intr_enable_q_i(reg2hw.intr_enable.cs_cmd_req_done.q),
    .reg2hw_intr_test_q_i  (reg2hw.intr_test.cs_cmd_req_done.q),
    .reg2hw_intr_test_qe_i (reg2hw.intr_test.cs_cmd_req_done.qe),
    .reg2hw_intr_state_q_i (reg2hw.intr_state.cs_cmd_req_done.q),
    .hw2reg_intr_state_de_o(hw2reg.intr_state.cs_cmd_req_done.de),
    .hw2reg_intr_state_d_o (hw2reg.intr_state.cs_cmd_req_done.d),
    .intr_o                (intr_cs_cmd_req_done_o)
  );
  prim_intr_hw #(
    .Width(1)
  ) u_intr_hw_cs_entropy_req (
    .clk_i                 (clk_i),
    .rst_ni                (rst_ni),
    .event_intr_i          (entropy_src_hw_if_o.es_req),
    .reg2hw_intr_enable_q_i(reg2hw.intr_enable.cs_entropy_req.q),
    .reg2hw_intr_test_q_i  (reg2hw.intr_test.cs_entropy_req.q),
    .reg2hw_intr_test_qe_i (reg2hw.intr_test.cs_entropy_req.qe),
    .reg2hw_intr_state_q_i (reg2hw.intr_state.cs_entropy_req.q),
    .hw2reg_intr_state_de_o(hw2reg.intr_state.cs_entropy_req.de),
    .hw2reg_intr_state_d_o (hw2reg.intr_state.cs_entropy_req.d),
    .intr_o                (intr_cs_entropy_req_o)
  );
  prim_intr_hw #(
    .Width(1)
  ) u_intr_hw_cs_hw_inst_exc (
    .clk_i                 (clk_i),
    .rst_ni                (rst_ni),
    .event_intr_i          (|hw_exception_sts),
    .reg2hw_intr_enable_q_i(reg2hw.intr_enable.cs_hw_inst_exc.q),
    .reg2hw_intr_test_q_i  (reg2hw.intr_test.cs_hw_inst_exc.q),
    .reg2hw_intr_test_qe_i (reg2hw.intr_test.cs_hw_inst_exc.qe),
    .reg2hw_intr_state_q_i (reg2hw.intr_state.cs_hw_inst_exc.q),
    .hw2reg_intr_state_de_o(hw2reg.intr_state.cs_hw_inst_exc.de),
    .hw2reg_intr_state_d_o (hw2reg.intr_state.cs_hw_inst_exc.d),
    .intr_o                (intr_cs_hw_inst_exc_o)
  );
  prim_intr_hw #(
    .Width(1)
  ) u_intr_hw_cs_fatal_err (
    .clk_i                 (clk_i),
    .rst_ni                (rst_ni),
    .event_intr_i          (event_cs_fatal_err),
    .reg2hw_intr_enable_q_i(reg2hw.intr_enable.cs_fatal_err.q),
    .reg2hw_intr_test_q_i  (reg2hw.intr_test.cs_fatal_err.q),
    .reg2hw_intr_test_qe_i (reg2hw.intr_test.cs_fatal_err.qe),
    .reg2hw_intr_state_q_i (reg2hw.intr_state.cs_fatal_err.q),
    .hw2reg_intr_state_de_o(hw2reg.intr_state.cs_fatal_err.de),
    .hw2reg_intr_state_d_o (hw2reg.intr_state.cs_fatal_err.d),
    .intr_o                (intr_cs_fatal_err_o)
  );
  
  
  
  
  logic fatal_loc_events;
  assign fatal_loc_events = block_encrypt_sm_err_sum || cmd_stage_sm_err_sum || ctr_drbg_sm_err_sum
                            || ctr_err_sum || err_code_test_bit[21];
  
  assign event_cs_fatal_err = fatal_loc_events || main_sm_err_sum || (cs_enable_fo[1] &&
                              ((|cmd_stage_sfifo_cmd_err_sum) || (|cmd_stage_sfifo_genbits_err_sum)
                              || fifo_write_err_sum || fifo_read_err_sum || fifo_status_err_sum));
  
  assign cmd_stage_sm_err_sum     = (|cmd_stage_sm_err)  || err_code_test_bit[20];
  assign main_sm_err_sum          = cs_main_sm_err       || err_code_test_bit[21];
  assign ctr_drbg_sm_err_sum      = ctr_drbg_sm_err      || err_code_test_bit[22];
  assign block_encrypt_sm_err_sum = block_encrypt_sm_err || err_code_test_bit[25];
  
  assign ctr_err_sum         = (|cmd_stage_ctr_err) || ctr_drbg_v_ctr_err || err_code_test_bit[26];
  assign fifo_write_err_sum  = (|cmd_stage_sfifo_genbits_err_wr) || (|cmd_stage_sfifo_cmd_err_wr) ||
                               err_code_test_bit[28];
  assign fifo_read_err_sum   = (|cmd_stage_sfifo_genbits_err_rd) || (|cmd_stage_sfifo_cmd_err_rd) ||
                               err_code_test_bit[29];
  assign fifo_status_err_sum = (|cmd_stage_sfifo_genbits_err_st) || (|cmd_stage_sfifo_cmd_err_st) ||
                               err_code_test_bit[30];
  
  assign hw2reg.err_code.sfifo_cmd_err.d = 1'b1;
  assign hw2reg.err_code.sfifo_cmd_err.de = cs_enable_fo[2] && (|cmd_stage_sfifo_cmd_err_sum);
  assign hw2reg.err_code.sfifo_genbits_err.d = 1'b1;
  assign hw2reg.err_code.sfifo_genbits_err.de = cs_enable_fo[3] &&
         (|cmd_stage_sfifo_genbits_err_sum);
  assign hw2reg.err_code.cmd_stage_sm_err.d = 1'b1;
  assign hw2reg.err_code.cmd_stage_sm_err.de = cs_enable_fo[19] && cmd_stage_sm_err_sum;
  assign hw2reg.err_code.main_sm_err.d = 1'b1;
  assign hw2reg.err_code.main_sm_err.de = cs_enable_fo[20] && main_sm_err_sum;
  assign hw2reg.err_code.ctr_drbg_sm_err.d = 1'b1;
  assign hw2reg.err_code.ctr_drbg_sm_err.de = cs_enable_fo[21] && ctr_drbg_sm_err_sum;
  assign hw2reg.err_code.aes_cipher_sm_err.d = 1'b1;
  assign hw2reg.err_code.aes_cipher_sm_err.de = cs_enable_fo[22] && block_encrypt_sm_err_sum;
  
  assign hw2reg.err_code.ctr_err.d = 1'b1;
  assign hw2reg.err_code.ctr_err.de = cs_enable_fo[23] && ctr_err_sum;
  assign hw2reg.err_code.fifo_write_err.d = 1'b1;
  assign hw2reg.err_code.fifo_write_err.de = cs_enable_fo[24] && fifo_write_err_sum;
  assign hw2reg.err_code.fifo_read_err.d = 1'b1;
  assign hw2reg.err_code.fifo_read_err.de = cs_enable_fo[25] && fifo_read_err_sum;
  assign hw2reg.err_code.fifo_state_err.d = 1'b1;
  assign hw2reg.err_code.fifo_state_err.de = cs_enable_fo[26] && fifo_status_err_sum;
  
  for (genvar i = 0; i < 31; i++) begin : gen_err_code_test_bit
    assign err_code_test_bit[i] = (reg2hw.err_code_test.q == i) && reg2hw.err_code_test.qe;
  end : gen_err_code_test_bit
  
  assign fatal_alert_o = event_cs_fatal_err;
  
  assign recov_alert_test_o = {
    reg2hw.alert_test.recov_alert.q &&
    reg2hw.alert_test.recov_alert.qe
  };
  assign fatal_alert_test_o = {
    reg2hw.alert_test.fatal_alert.q &&
    reg2hw.alert_test.fatal_alert.qe
  };
  assign recov_alert_event = cs_enable_pfa ||
         sw_app_enable_pfa ||
         read_int_state_pfa ||
         acmd_flag0_pfa ||
         |reseed_cnt_alert ||
         |invalid_cmd_seq_alert ||
         |invalid_acmd_alert ||
         cs_bus_cmp_alert;
  prim_edge_detector #(
    .Width(1),
    .ResetValue(0),
    .EnSync(0)
  ) u_prim_edge_detector_recov_alert (
    .clk_i,
    .rst_ni,
    .d_i(recov_alert_event),
    .q_sync_o(),
    .q_posedge_pulse_o(recov_alert_o),
    .q_negedge_pulse_o()
  );
  
  
  mubi4_t mubi_cs_enable;
  assign mubi_cs_enable = mubi4_t'(reg2hw.ctrl.enable.q);
  assign cs_enable_pfa = mubi4_test_invalid(mubi_cs_enable_fanout[0]);
  assign hw2reg.recov_alert_sts.enable_field_alert.de = cs_enable_pfa;
  assign hw2reg.recov_alert_sts.enable_field_alert.d  = cs_enable_pfa;
  for (genvar i = 1; i < CsEnableCopies; i = i+1) begin : gen_mubi_en_copies
    assign cs_enable_fo[i] = mubi4_test_true_strict(mubi_cs_enable_fanout[i]);
  end : gen_mubi_en_copies
  prim_mubi4_sync #(
    .NumCopies(CsEnableCopies),
    .AsyncOn(0)
  ) u_prim_mubi4_sync_cs_enable (
    .clk_i,
    .rst_ni,
    .mubi_i(mubi_cs_enable),
    .mubi_o(mubi_cs_enable_fanout)
  );
  
  mubi4_t mubi_sw_app_enable;
  mubi4_t [1:0] mubi_sw_app_enable_fanout;
  assign mubi_sw_app_enable = mubi4_t'(reg2hw.ctrl.sw_app_enable.q);
  assign sw_app_enable_pfe = mubi4_test_true_strict(mubi_sw_app_enable_fanout[0]);
  assign sw_app_enable_pfa = mubi4_test_invalid(mubi_sw_app_enable_fanout[1]);
  assign hw2reg.recov_alert_sts.sw_app_enable_field_alert.de = sw_app_enable_pfa;
  assign hw2reg.recov_alert_sts.sw_app_enable_field_alert.d  = sw_app_enable_pfa;
  prim_mubi4_sync #(
    .NumCopies(2),
    .AsyncOn(0)
  ) u_prim_mubi4_sync_sw_app_enable (
    .clk_i,
    .rst_ni,
    .mubi_i(mubi_sw_app_enable),
    .mubi_o(mubi_sw_app_enable_fanout)
  );
  
  mubi4_t mubi_read_int_state;
  mubi4_t [1:0] mubi_read_int_state_fanout;
  assign mubi_read_int_state = mubi4_t'(reg2hw.ctrl.read_int_state.q);
  assign read_int_state_pfe = mubi4_test_true_strict(mubi_read_int_state_fanout[0]);
  assign read_int_state_pfa = mubi4_test_invalid(mubi_read_int_state_fanout[1]);
  assign hw2reg.recov_alert_sts.read_int_state_field_alert.de = read_int_state_pfa;
  assign hw2reg.recov_alert_sts.read_int_state_field_alert.d  = read_int_state_pfa;
  prim_mubi4_sync #(
    .NumCopies(2),
    .AsyncOn(0)
  ) u_prim_mubi4_sync_read_int_state (
    .clk_i,
    .rst_ni,
    .mubi_i(mubi_read_int_state),
    .mubi_o(mubi_read_int_state_fanout)
  );
  
  mubi4_t mubi_fips_force_enable;
  mubi4_t [1:0] mubi_fips_force_enable_fanout;
  assign mubi_fips_force_enable = mubi4_t'(reg2hw.ctrl.fips_force_enable.q);
  assign fips_force_enable_pfe = mubi4_test_true_strict(mubi_fips_force_enable_fanout[0]);
  assign fips_force_enable_pfa = mubi4_test_invalid(mubi_fips_force_enable_fanout[1]);
  assign hw2reg.recov_alert_sts.fips_force_enable_field_alert.de = fips_force_enable_pfa;
  assign hw2reg.recov_alert_sts.fips_force_enable_field_alert.d  = fips_force_enable_pfa;
  prim_mubi4_sync #(
    .NumCopies(2),
    .AsyncOn(0)
  ) u_prim_mubi4_sync_fips_force_enable (
    .clk_i,
    .rst_ni,
    .mubi_i(mubi_fips_force_enable),
    .mubi_o(mubi_fips_force_enable_fanout)
  );
  
  assign sw_app_enable = sw_app_enable_pfe;
  assign read_int_state = read_int_state_pfe;
  assign fips_force_enable = fips_force_enable_pfe;
  
  
  
  
  
  
  
  
  for (genvar ai = 0; ai < NumApps; ai = ai+1) begin : gen_cmd_stage
    csrng_cmd_stage u_csrng_cmd_stage (
      .clk_i                        (clk_i),
      .rst_ni                       (rst_ni),
      .cs_enable_i                  (cs_enable_fo[27]),
      .cmd_stage_vld_i              (cmd_stage_vld[ai]),
      .cmd_stage_shid_i             (cmd_stage_shid[ai]),
      .cmd_stage_bus_i              (cmd_stage_bus[ai]),
      .cmd_stage_rdy_o              (cmd_stage_rdy[ai]),
      .reseed_cnt_reached_i         (reseed_cnt_reached_q[ai]),
      .reseed_cnt_alert_o           (reseed_cnt_alert[ai]),
      .invalid_cmd_seq_alert_o      (invalid_cmd_seq_alert[ai]),
      .invalid_acmd_alert_o         (invalid_acmd_alert[ai]),
      .cmd_arb_req_o                (cmd_arb_req[ai]),
      .cmd_arb_sop_o                (cmd_arb_sop[ai]),
      .cmd_arb_mop_o                (cmd_arb_mop[ai]),
      .cmd_arb_eop_o                (cmd_arb_eop[ai]),
      .cmd_arb_gnt_i                (cmd_arb_gnt[ai]),
      .cmd_arb_bus_o                (cmd_arb_bus[ai]),
      .cmd_ack_i                    (cmd_core_ack[ai]),
      .cmd_ack_sts_i                (cmd_core_ack_sts[ai]),
      .cmd_stage_ack_o              (cmd_stage_ack[ai]),
      .cmd_stage_ack_sts_o          (cmd_stage_ack_sts[ai]),
      .genbits_vld_i                (genbits_core_vld[ai]),
      .genbits_bus_i                (genbits_core_bus[ai]),
      .genbits_fips_i               (genbits_core_fips[ai]),
      .genbits_vld_o                (genbits_stage_vld[ai]),
      .genbits_rdy_i                (genbits_stage_rdy[ai]),
      .genbits_bus_o                (genbits_stage_bus[ai]),
      .genbits_fips_o               (genbits_stage_fips[ai]),
      .cmd_stage_sfifo_cmd_err_o    (cmd_stage_sfifo_cmd_err[ai]),
      .cmd_stage_sfifo_genbits_err_o(cmd_stage_sfifo_genbits_err[ai]),
      .cmd_gen_cnt_err_o            (cmd_stage_ctr_err[ai]),
      .cmd_stage_sm_err_o           (cmd_stage_sm_err[ai])
    );
    
    
    assign reseed_cnt_reached_d[ai] = (ctr_drbg_rsp_vld && (ctr_drbg_rsp_data.inst_id == ai)) ?
                                      (ctr_drbg_rsp_data.rs_ctr >= reg2hw.reseed_interval.q) :
                                      reseed_cnt_reached_q[ai];
  end : gen_cmd_stage
  
  
  assign cmd_stage_vld[NumApps-1]  = reg2hw.cmd_req.qe;
  assign cmd_stage_bus[NumApps-1]  = reg2hw.cmd_req.q;
  assign cmd_stage_shid[NumApps-1] = InstIdWidth'(NumApps-1);
  assign hw2reg.sw_cmd_sts.cmd_rdy.de = 1'b1;
  assign hw2reg.sw_cmd_sts.cmd_rdy.d  = !cmd_stage_vld[NumApps-1] && sw_rdy_sts_q;
  assign sw_rdy_sts_d =
         !cs_enable_fo[28] ? 1'b0 :
         cmd_stage_vld[NumApps-1] ? 1'b0 :
         cmd_stage_rdy[NumApps-1] ? 1'b1 :
         sw_rdy_sts_q;
  
  assign hw2reg.sw_cmd_sts.cmd_ack.de = 1'b1;
  assign hw2reg.sw_cmd_sts.cmd_ack.d = sw_sts_ack_d;
  assign sw_sts_ack_d =
         !cs_enable_fo[28] ? 1'b0 :
         cmd_stage_vld[NumApps-1] ? 1'b0 :
         cmd_stage_ack[NumApps-1] ? 1'b1 :
         sw_sts_ack_q;
  
  assign hw2reg.sw_cmd_sts.cmd_sts.de = cmd_stage_ack[NumApps-1];
  assign hw2reg.sw_cmd_sts.cmd_sts.d = cmd_stage_ack_sts[NumApps-1];
  
  assign hw2reg.genbits_vld.genbits_vld.d = genbits_stage_vld_sw;
  assign hw2reg.genbits_vld.genbits_fips.d = genbits_stage_fips_sw_q;
  assign hw2reg.genbits.d = (sw_app_enable && otp_sw_app_read_en[0]) ? genbits_stage_bus_sw : '0;
  assign genbits_stage_bus_rd_sw = reg2hw.genbits.re;
  assign otp_sw_app_read_en[0] = prim_mubi_pkg::mubi8_test_true_strict(otp_sw_app_read_en_mubi[0]);
  assign otp_sw_app_read_en[1] = prim_mubi_pkg::mubi8_test_true_strict(otp_sw_app_read_en_mubi[1]);
  prim_mubi8_sync #(
    .NumCopies(2),
    .AsyncOn(1)
  ) u_prim_mubi8_sync_sw_app_read (
    .clk_i,
    .rst_ni,
    .mubi_i(otp_en_csrng_sw_app_read_i),
    .mubi_o(otp_sw_app_read_en_mubi)
  );
  
  prim_packer_fifo #(
    .InW(BlkLen),
    .OutW(32),
    .ClearOnRead(1'b0)
  ) u_prim_packer_fifo_sw_genbits (
    .clk_i   (clk_i),
    .rst_ni  (rst_ni),
    .clr_i   (!cs_enable_fo[29]),
    .wvalid_i(genbits_stage_vld[NumApps-1]),
    .wdata_i (genbits_stage_bus[NumApps-1]),
    .wready_o(genbits_stage_rdy[NumApps-1]),
    .rvalid_o(genbits_stage_vld_sw),
    .rdata_o (genbits_stage_bus_sw),
    .rready_i(genbits_stage_bus_rd_sw),
    .depth_o ()
  );
  
  assign genbits_stage_fips_sw_d =
         (!cs_enable_fo[30]) ? 1'b0 :
         (genbits_stage_rdy[NumApps-1] && genbits_stage_vld[NumApps-1]) ?
                                          genbits_stage_fips[NumApps-1] :
                                          genbits_stage_fips_sw_q;
  
  
  
  
  
  
  
  assign cs_rdata_capt_vld = (genbits_stage_vld[NumApps-1] && genbits_stage_rdy[NumApps-1]);
  assign cs_rdata_capt_d = cs_rdata_capt_vld ? genbits_stage_bus[NumApps-1][63:0] : cs_rdata_capt_q;
  assign cs_rdata_capt_vld_d =
         !cs_enable_fo[31] ? 1'b0 :
         cs_rdata_capt_vld ? 1'b1 :
         cs_rdata_capt_vld_q;
  
  assign cs_bus_cmp_alert = cs_rdata_capt_vld && cs_rdata_capt_vld_q &&
         (cs_rdata_capt_q == genbits_stage_bus[NumApps-1][63:0]); 
  assign hw2reg.recov_alert_sts.cs_bus_cmp_alert.de = cs_bus_cmp_alert;
  assign hw2reg.recov_alert_sts.cs_bus_cmp_alert.d  = cs_bus_cmp_alert;
  assign hw2reg.recov_alert_sts.cmd_stage_invalid_acmd_alert.de = |invalid_acmd_alert;
  assign hw2reg.recov_alert_sts.cmd_stage_invalid_acmd_alert.d  = |invalid_acmd_alert;
  assign hw2reg.recov_alert_sts.cmd_stage_invalid_cmd_seq_alert.de = |invalid_cmd_seq_alert;
  assign hw2reg.recov_alert_sts.cmd_stage_invalid_cmd_seq_alert.d  = |invalid_cmd_seq_alert;
  assign hw2reg.recov_alert_sts.cmd_stage_reseed_cnt_alert.de = |reseed_cnt_alert;
  assign hw2reg.recov_alert_sts.cmd_stage_reseed_cnt_alert.d  = |reseed_cnt_alert;
  
  for (genvar hai = 0; hai < (NumApps-1); hai = hai+1) begin : gen_app_if
    
    assign cmd_stage_vld[hai]  = csrng_cmd_i[hai].csrng_req_valid;
    assign cmd_stage_shid[hai] = hai;
    assign cmd_stage_bus[hai]  = csrng_cmd_i[hai].csrng_req_bus;
    assign csrng_cmd_o[hai].csrng_req_ready = cmd_stage_rdy[hai];
    
    assign csrng_cmd_o[hai].csrng_rsp_ack = cmd_stage_ack[hai];
    assign csrng_cmd_o[hai].csrng_rsp_sts = cmd_stage_ack_sts[hai];
    
    assign csrng_cmd_o[hai].genbits_valid = genbits_stage_vld[hai];
    assign csrng_cmd_o[hai].genbits_fips  = genbits_stage_fips[hai];
    assign csrng_cmd_o[hai].genbits_bus   = genbits_stage_bus[hai];
    assign genbits_stage_rdy[hai] = csrng_cmd_i[hai].genbits_ready;
  end : gen_app_if
  
  for (genvar i = 0; i < 16; i = i+1) begin : gen_app_if_sts
    if (i < NumApps) begin : gen_assign
      assign hw_exception_sts[i] = cmd_stage_ack[i] && (cmd_stage_ack_sts[i] != CMD_STS_SUCCESS);
    end else begin : gen_dummy_assign
      assign hw_exception_sts[i] = 1'b0;
    end
  end : gen_app_if_sts
  
  for (genvar i = 0; i < NumApps; i = i+1) begin : gen_fifo_sts
    assign cmd_stage_sfifo_cmd_err_sum[i] = (|cmd_stage_sfifo_cmd_err[i] ||
                                             err_code_test_bit[0]);
    assign cmd_stage_sfifo_cmd_err_wr[i] = cmd_stage_sfifo_cmd_err[i][2];
    assign cmd_stage_sfifo_cmd_err_rd[i] = cmd_stage_sfifo_cmd_err[i][1];
    assign cmd_stage_sfifo_cmd_err_st[i] = cmd_stage_sfifo_cmd_err[i][0];
    assign cmd_stage_sfifo_genbits_err_sum[i] = (|cmd_stage_sfifo_genbits_err[i] ||
                                                 err_code_test_bit[1]);
    assign cmd_stage_sfifo_genbits_err_wr[i] = cmd_stage_sfifo_genbits_err[i][2];
    assign cmd_stage_sfifo_genbits_err_rd[i] = cmd_stage_sfifo_genbits_err[i][1];
    assign cmd_stage_sfifo_genbits_err_st[i] = cmd_stage_sfifo_genbits_err[i][0];
  end : gen_fifo_sts
  
  
  
  
  
  
  
  assign cmd_arb_idx_d = (acmd_avail && acmd_accept) ? cmd_arb_idx : cmd_arb_idx_q;
  assign acmd_sop = cmd_arb_sop[cmd_arb_idx_q]; 
  assign acmd_mop = cmd_arb_mop[cmd_arb_idx_q]; 
  assign acmd_eop = cmd_arb_eop[cmd_arb_idx_q]; 
  assign acmd_bus = cmd_arb_bus[cmd_arb_idx_q]; 
  prim_arbiter_ppc #(
    .EnDataPort(0),    
    .N(NumApps),  
    .DW(1) 
  ) u_prim_arbiter_ppc_acmd (
    .clk_i    (clk_i),
    .rst_ni   (rst_ni),
    .req_chk_i(cs_enable_fo[1]),
    .req_i    (cmd_arb_req),
    .data_i   ('{default: 1'b0}),
    .gnt_o    (cmd_arb_gnt),
    .idx_o    (cmd_arb_idx),
    .valid_o  (acmd_avail), 
    .data_o   (), 
    .ready_i  (acmd_accept) 
  );
  assign acmd_flag0_pfa = mubi4_test_invalid(flag0_q);
  assign hw2reg.recov_alert_sts.acmd_flag0_field_alert.de = acmd_flag0_pfa;
  assign hw2reg.recov_alert_sts.acmd_flag0_field_alert.d  = acmd_flag0_pfa;
  
  assign acmd_hold = acmd_sop ? acmd_e'(acmd_bus[CmdWidth-1:0]) : acmd_q;
  
  assign acmd_d =
         (!cs_enable_fo[32]) ? INV :
         acmd_sop ? acmd_e'(acmd_bus[CmdWidth-1:0]) :
         acmd_q;
  assign inst_id_d =
         (!cs_enable_fo[33]) ? '0 :
         acmd_sop ? acmd_bus[12 +: NumAppsLg] :
         inst_id_q;
  assign gen_last_d =
         (!cs_enable_fo[34]) ? '0 :
         acmd_sop ? acmd_bus[16] :
         gen_last_q;
  assign flag0_d =
         (!cs_enable_fo[35]) ? prim_mubi_pkg::MuBi4False :
         (acmd_sop && ((acmd_bus[2:0] == INS) || (acmd_bus[2:0] == RES))) ?
          mubi4_t'(acmd_bus[11:8]) : flag0_q;
  
  mubi4_t mubi_flag0;
  assign mubi_flag0 = flag0_q;
  for (genvar i = 0; i < Flag0Copies; i = i+1) begin : gen_mubi_flag0_copies
    assign flag0_fo[i] = mubi4_test_true_strict(mubi_flag0_fanout[i]);
  end : gen_mubi_flag0_copies
  prim_mubi4_sync #(
    .NumCopies(Flag0Copies),
    .AsyncOn(0)
  ) u_prim_mubi4_sync_flag0 (
    .clk_i,
    .rst_ni,
    .mubi_i(mubi_flag0),
    .mubi_o(mubi_flag0_fanout)
  );
  
  
  csrng_main_sm u_csrng_main_sm (
    .clk_i                 (clk_i),
    .rst_ni                (rst_ni),
    .enable_i              (cs_enable_fo[36]),
    .acmd_avail_i          (acmd_avail),
    .acmd_accept_o         (acmd_accept),
    .acmd_i                (acmd_hold),
    .acmd_eop_i            (acmd_eop),
    .flag0_i               (flag0_fo[0]),
    .cmd_entropy_req_o     (cmd_entropy_req),
    .cmd_entropy_avail_i   (cmd_entropy_avail),
    .cmd_vld_o             (main_sm_cmd_vld),
    .cmd_rdy_i             (ctr_drbg_req_rdy),
    .clr_adata_packer_o    (clr_adata_packer),
    .cmd_complete_i        (ctr_drbg_rsp_vld),
    .local_escalate_i      (fatal_loc_events),
    .main_sm_state_o       (cs_main_sm_state),
    .main_sm_err_o         (cs_main_sm_err)
  );
  
  assign cmd_entropy_avail = entropy_src_hw_if_i.es_ack;
  for (genvar csi = 0; csi < NumApps; csi = csi+1) begin : gen_cmd_ack
    assign cmd_core_ack[csi] = ctr_drbg_rsp_vld && (ctr_drbg_rsp_data.inst_id == csi);
    assign cmd_core_ack_sts[csi] = ctr_drbg_rsp_sts;
    assign genbits_core_vld[csi] = ctr_drbg_bits_vld && (ctr_drbg_rsp_data.inst_id == csi);
    assign genbits_core_bus[csi] = ctr_drbg_bits_data;
    assign genbits_core_fips[csi] = ctr_drbg_bits_fips;
  end : gen_cmd_ack
  prim_packer_fifo #(
    .InW(32),
    .OutW(SeedLen),
    .ClearOnRead(1'b1)
  ) u_prim_packer_fifo_adata (
    .clk_i   (clk_i),
    .rst_ni  (rst_ni),
    .clr_i   (!cs_enable_fo[37] || packer_adata_clr),
    .wvalid_i(acmd_mop),
    .wdata_i (acmd_bus),
    .wready_o(),
    .rvalid_o(),
    .rdata_o (packer_adata),
    .rready_i(packer_adata_pop),
    .depth_o (packer_adata_depth)
  );
  assign packer_adata_pop = cs_enable_fo[38] &&
         clr_adata_packer && (packer_adata_depth == ADataDepthClog'(CmdMaxClen));
  assign packer_adata_clr = cs_enable_fo[39] &&
         clr_adata_packer && (packer_adata_depth < ADataDepthClog'(CmdMaxClen));
  
  
  
  
  assign state_db_reg_read_en = cs_enable_fo[40] && read_int_state && otp_sw_app_read_en[1];
  csrng_state_db u_csrng_state_db (
    .clk_i   (clk_i),
    .rst_ni  (rst_ni),
    .enable_i(cs_enable_fo[41]),
    .rd_inst_id_i(inst_id_q),
    .rd_state_o  (state_db_rd_data),
    .wr_vld_i   (state_db_wr_vld),
    .wr_data_i  (ctr_drbg_rsp_data),
    .reg_rd_otp_en_i    (state_db_reg_read_en),
    .reg_rd_regfile_en_i(reg2hw.int_state_read_enable.q),
    .reg_rd_id_vld_i(reg2hw.int_state_num.qe),
    .reg_rd_id_i    (reg2hw.int_state_num.q),
    .reg_rd_strb_i  (reg2hw.int_state_val.re),
    .reg_rd_val_o   (hw2reg.int_state_val.d),
    .reseed_counter_o(reseed_counter)
  );
  
  always_comb begin : reseed_counter_assign
    for (int i = 0; i < NumApps; i++) begin
      hw2reg.reseed_counter[i].d = reseed_counter[i];
    end
  end
  
  
  
  
  assign entropy_src_hw_if_o.es_req = cs_enable_fo[43] && cmd_entropy_req;
  
  assign seed_diversification = lc_hw_debug_on_fo[0] ? RndCnstCsKeymgrDivNonProduction :
                                                       RndCnstCsKeymgrDivProduction;
  
  assign entropy_src_seed_d =
         flag0_fo[1] ? '0 : 
         cmd_entropy_req && cmd_entropy_avail ?
            (entropy_src_hw_if_i.es_bits ^ seed_diversification) :
         entropy_src_seed_q;
  assign entropy_src_fips_d =
         
         
         fips_force_enable && reg2hw.fips_force.q[inst_id_d] ? 1'b1 :
         flag0_fo[2] ? '0 : 
         cmd_entropy_req && cmd_entropy_avail ? entropy_src_hw_if_i.es_fips :
         entropy_src_fips_q;
  
  
  
  assign ctr_drbg_req_vld = !cs_enable_fo[45] ? 1'b0 : main_sm_cmd_vld;
  assign ctr_drbg_cmd_d   = !cs_enable_fo[44] ?  INV : acmd_hold;
  assign ctr_drbg_req_data = '{
    inst_id: inst_id_q,
    cmd:     ctr_drbg_cmd_q,
    key:     state_db_rd_data.key,
    v:       state_db_rd_data.v,
    pdata:   packer_adata,
    rs_ctr:  state_db_rd_data.rs_ctr,
    fips:    state_db_rd_data.fips
  };
  csrng_ctr_drbg u_csrng_ctr_drbg (
    .clk_i   (clk_i),
    .rst_ni  (rst_ni),
    .enable_i(cs_enable_fo[49]),
    .req_vld_i         (ctr_drbg_req_vld),
    .req_rdy_o         (ctr_drbg_req_rdy),
    .req_data_i        (ctr_drbg_req_data),
    .req_entropy_i     (entropy_src_seed_q),
    .req_entropy_fips_i(entropy_src_fips_q),
    .req_glast_i       (gen_last_q),
    .rsp_vld_o (ctr_drbg_rsp_vld),
    .rsp_data_o(ctr_drbg_rsp_data),
    .rsp_sts_o (ctr_drbg_rsp_sts),
    .bits_vld_o (ctr_drbg_bits_vld),
    .bits_data_o(ctr_drbg_bits_data),
    .bits_fips_o(ctr_drbg_bits_fips),
    .state_db_wr_o(state_db_wr_vld),
    .block_encrypt_req_vld_o (block_encrypt_req_vld),
    .block_encrypt_req_rdy_i (block_encrypt_req_rdy),
    .block_encrypt_req_data_o(block_encrypt_req_data),
    .block_encrypt_rsp_vld_i (block_encrypt_rsp_vld),
    .block_encrypt_rsp_rdy_o (block_encrypt_rsp_rdy),
    .block_encrypt_rsp_data_i(block_encrypt_rsp_data),
    .ctr_err_o(ctr_drbg_v_ctr_err),
    .sm_err_o (ctr_drbg_sm_err)
  );
  
  
  
  csrng_block_encrypt #(
    .SBoxImpl(SBoxImpl)
  ) u_csrng_block_encrypt (
    .clk_i   (clk_i),
    .rst_ni  (rst_ni),
    .enable_i(cs_enable_fo[48]),
    .req_vld_i (block_encrypt_req_vld),
    .req_rdy_o (block_encrypt_req_rdy),
    .req_data_i(block_encrypt_req_data),
    .rsp_vld_o (block_encrypt_rsp_vld),
    .rsp_rdy_i (block_encrypt_rsp_rdy),
    .rsp_data_o(block_encrypt_rsp_data),
    .cipher_sm_err_o(block_encrypt_sm_err)
  );
  
  
  
  
  
  
  lc_ctrl_pkg::lc_tx_t [LcHwDebugCopies-1:0] lc_hw_debug_en_out;
  prim_lc_sync #(
    .NumCopies(LcHwDebugCopies)
  ) u_prim_lc_sync (
    .clk_i,
    .rst_ni,
    .lc_en_i(lc_hw_debug_en_i),
    .lc_en_o({lc_hw_debug_en_out})
  );
  for (genvar i = 0; i < LcHwDebugCopies; i = i+1) begin : gen_lc_dbg_copies
    assign lc_hw_debug_on_fo[i] = lc_ctrl_pkg::lc_tx_test_true_strict(lc_hw_debug_en_out[i]);
  end : gen_lc_dbg_copies
  
  
  
  assign hw2reg.main_sm_state.de = 1'b1;
  assign hw2reg.main_sm_state.d  = cs_main_sm_state;
  
  
  
  
  assign hw2reg.hw_exc_sts.de = cs_enable_fo[50];
  assign hw2reg.hw_exc_sts.d  = hw_exception_sts;
  
  logic               unused_err_code_test_bit;
  logic               unused_enable_fo;
  logic               unused_reg2hw_genbits;
  logic               unused_int_state_val;
  logic               unused_reseed_interval;
  logic [SeedLen-1:0] unused_gen_rsp_pdata;
  logic               unused_state_db_inst_state;
  assign unused_err_code_test_bit = err_code_test_bit[27] || (|err_code_test_bit[24:23]) ||
                                    (|err_code_test_bit[19:2]);
  assign unused_enable_fo = (|cs_enable_fo[47:46]) || cs_enable_fo[42] || (|cs_enable_fo[18:4]);
  assign unused_reg2hw_genbits = (|reg2hw.genbits.q);
  assign unused_int_state_val = (|reg2hw.int_state_val.q);
  assign unused_reseed_interval = reg2hw.reseed_interval.qe;
  assign unused_gen_rsp_pdata = ctr_drbg_rsp_data.pdata;
  assign unused_state_db_inst_state = state_db_rd_data.inst_state;
  
  
  
`ifdef INC_ASSERT
  logic state_db_zeroize;
  assign state_db_zeroize = state_db_wr_vld && (ctr_drbg_rsp_data.cmd == UNI);
  `ASSERT(CsrngUniZeroizeFips_A, state_db_zeroize -> (ctr_drbg_rsp_data.fips   == '0))
  `ASSERT(CsrngUniZeroizeKey_A,  state_db_zeroize -> (ctr_drbg_rsp_data.key    == '0))
  `ASSERT(CsrngUniZeroizeV_A,    state_db_zeroize -> (ctr_drbg_rsp_data.v      == '0))
  `ASSERT(CsrngUniZeroizeRc_A,   state_db_zeroize -> (ctr_drbg_rsp_data.rs_ctr == '0))
  `ASSERT(CsrngUniZeroizeSts_A,  state_db_zeroize -> (ctr_drbg_rsp_sts == CMD_STS_SUCCESS))`endif
endmodule 

`ifndef PRIM_ASSERT_SV
`define PRIM_ASSERT_SV
`define ASSERT_DEFAULT_CLK clk_i
`define ASSERT_DEFAULT_RST !rst_ni
`define PRIM_STRINGIFY(__x) `"__x`"
`define ASSERT_ERROR(__name)                                                             \
`ifdef UVM                                                                               \
  uvm_pkg::uvm_report_error("ASSERT FAILED", `PRIM_STRINGIFY(__name), uvm_pkg::UVM_NONE, \
                            `__FILE__, `__LINE__, "", 1);                                \
`else                                                                                    \
  $error("%0t: (%0s:%0d) [%m] [ASSERT FAILED] %0s", $time, `__FILE__, `__LINE__,         \
         `PRIM_STRINGIFY(__name));                                                       \
`endif
`define ASSERT_STATIC_LINT_ERROR(__name, __prop)     \
  localparam int __name = (__prop) ? 1 : 2;          \
  always_comb begin                                  \
    logic unused_assert_static_lint_error;           \
    unused_assert_static_lint_error = __name'(1'b1); \
  end
`define ASSERT_STATIC_IN_PACKAGE(__name, __prop)              \
  function automatic bit assert_static_in_package_``__name(); \
    bit unused_bit [((__prop) ? 1 : -1)];                     \
    unused_bit = '{default: 1'b0};                            \
    return unused_bit[0];                                     \
  endfunction
`ifdef VERILATOR
 `include "prim_assert_dummy_macros.svh"`elsif SYNTHESIS
 `include "prim_assert_dummy_macros.svh"`elsif YOSYS
 `include "prim_assert_yosys_macros.svh"
 `define INC_ASSERT`else
 
`define ASSERT_I(__name, __prop) \
  __name: assert (__prop)        \
    else begin                   \
      `ASSERT_ERROR(__name)      \
    end
`define ASSERT_INIT(__name, __prop)                                                  \
`ifdef FPV_ON                                                                        \
  if (!(__prop)) $fatal(2, "Fatal static assertion [%s]: (%s) is not true.",         \
                        (__name), (__prop));                                         \
`else                                                                                \
  initial begin                                                                      \
    __name: assert (__prop)                                                          \
      else begin                                                                     \
        `ASSERT_ERROR(__name)                                                        \
      end                                                                            \
  end                                                                                \
`endif
`define ASSERT_INIT_NET(__name, __prop)                                                   \
  initial begin                                                                      \
    
    
    
    #1ps;                                                                            \
    __name: assert (__prop)                                                          \
      else begin                                                                     \
        `ASSERT_ERROR(__name)                                                        \
      end                                                                            \
  end                                                                                \
`define ASSERT_FINAL(__name, __prop)                                         \
`ifndef FPV_ON                                                               \
  final begin                                                                \
    __name: assert (__prop || $test$plusargs("disable_assert_final_checks")) \
      else begin                                                             \
        `ASSERT_ERROR(__name)                                                \
      end                                                                    \
  end                                                                        \
`endif
`define ASSERT_AT_RESET(__name, __prop, __rst = `ASSERT_DEFAULT_RST)          \
  
  
  
  
  
  
  
  
  
  
`ifndef FPV_ON                                                                \
  __name: assert property (@(posedge __rst) $isunknown(__rst) || (__prop))    \
`else                                                                         \
  __name: assert property (@(posedge __rst) (__prop))                         \
`endif                                                                        \
    else begin                                                                \
      `ASSERT_ERROR(__name)                                                   \
    end
`define ASSERT_AT_RESET_AND_FINAL(__name, __prop, __rst = `ASSERT_DEFAULT_RST) \
    `ASSERT_AT_RESET(AtReset_``__name``, __prop, __rst)                        \
    `ASSERT_FINAL(Final_``__name``, __prop)
`define ASSERT(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  __name: assert property (@(posedge __clk) disable iff ((__rst) !== '0) (__prop))       \
    else begin                                                                           \
      `ASSERT_ERROR(__name)                                                              \
    end
`define ASSERT_NEVER(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  __name: assert property (@(posedge __clk) disable iff ((__rst) !== '0) not (__prop))         \
    else begin                                                                                 \
      `ASSERT_ERROR(__name)                                                                    \
    end
`define ASSERT_KNOWN(__name, __sig, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
`ifndef FPV_ON                                                                                \
  `ASSERT(__name, !$isunknown(__sig), __clk, __rst)                                           \
`endif
`define COVER(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  __name: cover property (@(posedge __clk) disable iff ((__rst) !== '0) (__prop));
`define ASSUME(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  __name: assume property (@(posedge __clk) disable iff ((__rst) !== '0) (__prop))       \
    else begin                                                                           \
      `ASSERT_ERROR(__name)                                                              \
    end
`define ASSUME_I(__name, __prop) \
  __name: assume (__prop)        \
    else begin                   \
      `ASSERT_ERROR(__name)      \
    end
 `define INC_ASSERT
`endif
`define ASSERT_PULSE(__name, __sig, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  `ASSERT(__name, $rose(__sig) |=> !(__sig), __clk, __rst)
`define ASSERT_IF(__name, __prop, __enable, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  `ASSERT(__name, (__enable) |-> (__prop), __clk, __rst)
`define ASSERT_KNOWN_IF(__name, __sig, __enable, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
`ifndef FPV_ON                                                                                             \
  `ASSERT_KNOWN(__name``KnownEnable, __enable, __clk, __rst)                                               \
  `ASSERT_IF(__name, !$isunknown(__sig), __enable, __clk, __rst)                                           \
`endif
`define ASSUME_FPV(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
`ifdef FPV_ON                                                                                \
   `ASSUME(__name, __prop, __clk, __rst)                                                     \
`endif
`define ASSUME_I_FPV(__name, __prop) \
`ifdef FPV_ON                        \
   `ASSUME_I(__name, __prop)         \
`endif
`define COVER_FPV(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
`ifdef FPV_ON                                                                               \
   `COVER(__name, __prop, __clk, __rst)                                                     \
`endif
`define ASSERT_FPV_LINEAR_FSM(__name, __state, __type, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  `ifdef INC_ASSERT                                                                                              \
     bit __name``_cond;                                                                                          \
     always_ff @(posedge __clk or posedge __rst) begin                                                           \
       if (__rst) begin                                                                                          \
         __name``_cond <= 0;                                                                                     \
       end else begin                                                                                            \
         __name``_cond <= 1;                                                                                     \
       end                                                                                                       \
     end                                                                                                         \
     property __name``_p;                                                                                        \
       __type initial_state;                                                                                     \
       (!$stable(__state) & __name``_cond, initial_state = $past(__state)) |->                                   \
           (__state != initial_state) until !(__name``_cond);                                                    \
     endproperty                                                                                                 \
   `ASSERT(__name, __name``_p, __clk, 0)                                                                         \
  `endif
`ifndef PRIM_ASSERT_SEC_CM_SVH
`define PRIM_ASSERT_SEC_CM_SVH
`define _SEC_CM_ALERT_MAX_CYC 30
`define ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, ERR_NAME_, CLK_, RST_) \
  `ASSERT(FpvSecCm``NAME_``,                                                                    \
          $rose(HIER_.ERR_NAME_) && !(GATE_) |-> ##[0:MAX_CYCLES_] (ERR_),                      \
          CLK_, RST_)                                                                           \
  `ifdef INC_ASSERT                                                                             \
    assign HIER_.unused_assert_connected = 1'b1;                                                \
  `endif
`define ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, ERR_NAME_)    \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, (ALERT_.alert_p), GATE_, MAX_CYCLES_, ERR_NAME_, \
                            `ASSERT_DEFAULT_CLK, `ASSERT_DEFAULT_RST)                      \
  `ASSUME_FPV(``NAME_``TriggerAfterAlertInit_S,                                            \
              $stable(rst_ni) == 0 |-> HIER_.ERR_NAME_ == 0 [*10])
`define ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_IN_, GATE_, MAX_CYCLES_, ERR_NAME_) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ALERT_IN_, GATE_, MAX_CYCLES_, ERR_NAME_,           \
                            `ASSERT_DEFAULT_CLK, `ASSERT_DEFAULT_RST)
`define ASSERT_PRIM_COUNT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_DOUBLE_LFSR_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_FSM_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, unused_err_o)
`define ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_REG_WE_ONEHOT_ERROR_TRIGGER_ALERT(NAME_, REG_TOP_HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ALERT(NAME_, \
    REG_TOP_HIER_.u_prim_reg_we_check.u_prim_onehot_check, ALERT_, GATE_, MAX_CYCLES_)
`define ASSERT_PRIM_FIFO_SYNC_SINGLETON_ERROR_TRIGGER_ALERT(NAME, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_COUNT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_DOUBLE_LFSR_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_FSM_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, unused_err_o)
`define ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_REG_WE_ONEHOT_ERROR_TRIGGER_ALERT_IN(NAME_, REG_TOP_HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ALERT_IN(NAME_, \
    REG_TOP_HIER_.u_prim_reg_we_check.u_prim_onehot_check, ALERT_, GATE_, MAX_CYCLES_)
`define ASSERT_PRIM_FIFO_SYNC_SINGLETON_ERROR_TRIGGER_ALERT_IN(NAME, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_FSM_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = 2, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, unused_err_o, CLK_, RST_)
`define ASSERT_PRIM_COUNT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = 2, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, err_o, CLK_, RST_)
`define ASSERT_PRIM_DOUBLE_LFSR_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = 2, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, err_o, CLK_, RST_)
`define ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, err_o, CLK_, RST_)
`define ASSERT_PRIM_REG_WE_ONEHOT_ERROR_TRIGGER_ERR(NAME_, REG_TOP_HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ERR(NAME_, \
    REG_TOP_HIER_.u_prim_reg_we_check.u_prim_onehot_check, ERR_, GATE_, MAX_CYCLES_, CLK_, RST_)
`endif 
`ifndef PRIM_FLOP_MACROS_SV
`define PRIM_FLOP_MACROS_SV
`define PRIM_FLOP_CLK clk_i
`define PRIM_FLOP_RST rst_ni
`define PRIM_FLOP_RESVAL '0
`define PRIM_FLOP_A(__d, __q, __resval = `PRIM_FLOP_RESVAL, __clk = `PRIM_FLOP_CLK, __rst_n = `PRIM_FLOP_RST) \
  always_ff @(posedge __clk or negedge __rst_n) begin \
    if (!__rst_n) begin                               \
      __q <= __resval;                                \
    end else begin                                    \
      __q <= __d;                                     \
    end                                               \
  end
`define PRIM_FLOP_SPARSE_FSM(__name, __d, __q, __type, __resval = `PRIM_FLOP_RESVAL, __clk = `PRIM_FLOP_CLK, __rst_n = `PRIM_FLOP_RST, __alert_trigger_sva_en = 1) \
  `ifdef SIMULATION                                   \
    prim_sparse_fsm_flop #(                           \
      .StateEnumT(__type),                            \
      .Width($bits(__type)),                          \
      .ResetValue($bits(__type)'(__resval)),          \
      .EnableAlertTriggerSVA(__alert_trigger_sva_en), \
      .CustomForceName(`PRIM_STRINGIFY(__q))          \
    ) __name (                                        \
      .clk_i   ( __clk   ),                           \
      .rst_ni  ( __rst_n ),                           \
      .state_i ( __d     ),                           \
      .state_o (         )                            \
    );                                                \
    `PRIM_FLOP_A(__d, __q, __resval, __clk, __rst_n)  \
    `ASSERT(``__name``_A, __q === ``__name``.state_o) \
  `else                                               \
    prim_sparse_fsm_flop #(                           \
      .StateEnumT(__type),                            \
      .Width($bits(__type)),                          \
      .ResetValue($bits(__type)'(__resval)),          \
      .EnableAlertTriggerSVA(__alert_trigger_sva_en)  \
    ) __name (                                        \
      .clk_i   ( __clk   ),                           \
      .rst_ni  ( __rst_n ),                           \
      .state_i ( __d     ),                           \
      .state_o ( __q     )                            \
    );                                                \
  `endif
`endif 
`endif 
module csrng_ctr_drbg import csrng_pkg::*; (
  input  logic               clk_i,
  input  logic               rst_ni,
  
  input  logic               enable_i,
  
  input  logic               req_vld_i,
  output logic               req_rdy_o,
  input  csrng_core_data_t   req_data_i,
  input  logic [SeedLen-1:0] req_entropy_i,
  input  logic               req_entropy_fips_i,
  input  logic               req_glast_i,
  
  output logic               state_db_wr_o,
  output logic               rsp_vld_o,
  output csrng_core_data_t   rsp_data_o,
  output csrng_cmd_sts_e     rsp_sts_o,
  
  output logic               bits_vld_o,
  output logic  [BlkLen-1:0] bits_data_o,
  output logic               bits_fips_o,
  
  output logic               block_encrypt_req_vld_o,
  input  logic               block_encrypt_req_rdy_i,
  output csrng_key_v_t       block_encrypt_req_data_o,
  
  input  logic               block_encrypt_rsp_vld_i,
  output logic               block_encrypt_rsp_rdy_o,
  input  logic  [BlkLen-1:0] block_encrypt_rsp_data_i,
  
  output logic               ctr_err_o,
  output logic               sm_err_o
);
  import csrng_reg_pkg::NumApps;
  
  localparam int unsigned NumBlkPerUpd   = SeedLen/BlkLen;
  localparam int unsigned NumBlkPerUpdLg = $clog2(NumBlkPerUpd);
  
  typedef enum logic [1:0] {
    UPD_BEGIN,
    GEN_LOOP,
    UPD_FINAL
  } gen_subcmd_e;
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  localparam int StateWidth = 6;
  typedef enum logic [StateWidth-1:0] {
    Idle       = 6'b101110,
    CtrInc     = 6'b100001,
    ReqSend    = 6'b110100,
    RspWait    = 6'b010111,
    Hndshk     = 6'b001101,
    HndshkGen  = 6'b011000,
    HndshkLoad = 6'b111011,
    Error      = 6'b000010
  } state_e;
  state_e state_q, state_d;
  
  `PRIM_FLOP_SPARSE_FSM(u_state_regs, state_d, state_q, state_e, Idle)
  
  
  
  
  csrng_core_data_t   core_data;
  
  logic  [BlkLen-1:0] v_ctr_sized;
  logic  [CtrLen-1:0] v_ctr;
  logic               v_ctr_load;
  logic               v_ctr_inc;
  csrng_key_v_t       concat_key_v;
  logic               concat_ctr_inc;
  logic               concat_ctr_done;
  
  
  
  
  
  
  
  
  
  
  
  
  
  csrng_key_v_t [NumApps-1:0] generate_adata_q, generate_adata_d;
  logic         [NumApps-1:0] generate_adata_vld_q, generate_adata_vld_d;
  
  logic        [SeedLen-1:0] concat_key_v_q, concat_key_v_d;
  logic [NumBlkPerUpdLg-1:0] concat_ctr_q, concat_ctr_d;
  
  gen_subcmd_e gen_subcmd_q, gen_subcmd_d;
  always_ff @(posedge clk_i or negedge rst_ni) begin
    if (!rst_ni) begin
      generate_adata_q     <= '{default: '0};
      generate_adata_vld_q <= '0;
      concat_ctr_q         <= '0;
      concat_key_v_q       <= '0;
      gen_subcmd_q         <= UPD_BEGIN;
    end else begin
      generate_adata_q     <= generate_adata_d;
      generate_adata_vld_q <= generate_adata_vld_d;
      concat_ctr_q         <= concat_ctr_d;
      concat_key_v_q       <= concat_key_v_d;
      gen_subcmd_q         <= gen_subcmd_d;
    end
  end
  
  
  
  always_comb begin
    core_data = req_data_i;
    unique case (req_data_i.cmd)
      INS: begin
        
        core_data.key    = '0;
        core_data.v      = '0;
        core_data.rs_ctr = '0;
        core_data.pdata  = req_data_i.pdata ^ req_entropy_i;
        core_data.fips   = req_entropy_fips_i;
      end
      RES: begin
        
        core_data.rs_ctr = '0;
        core_data.pdata  = req_data_i.pdata ^ req_entropy_i;
        core_data.fips   = req_entropy_fips_i;
      end
      UPD, GEN: begin
        
      end
      UNI: begin
        
        core_data.key    = '0;
        core_data.v      = '0;
        core_data.rs_ctr = '0;
        core_data.pdata  = '0;
        core_data.fips   = 1'b0;
      end
      default: begin
        
        core_data.cmd = INV;
      end
    endcase
  end
  
  
  
  for (genvar i = 0; i < NumApps; i++) begin : g_assign_gen_adata
    logic capt_adata;
    logic clear_adata_vld;
    
    
    assign capt_adata = req_vld_i && (core_data.cmd == GEN) && (core_data.inst_id == i) &&
                        !generate_adata_vld_q[i];
    assign clear_adata_vld = rsp_vld_o && req_glast_i && (core_data.inst_id == i);
    always_comb begin
      generate_adata_vld_d[i] = generate_adata_vld_q[i];
      generate_adata_d[i]     = generate_adata_q[i];
      if (!enable_i) begin
        generate_adata_vld_d[i] = 1'b0;
        generate_adata_d[i]     = '0;
      end else if (capt_adata) begin
        generate_adata_vld_d[i] = 1'b1;
        generate_adata_d[i]     = core_data.pdata;
      end else if (clear_adata_vld) begin
        generate_adata_vld_d[i] = 1'b0;
      end
    end
  end
  
  
  
  
  prim_count #(
    .Width(CtrLen),
    .PossibleActions(prim_count_pkg::Clr |
                     prim_count_pkg::Set |
                     prim_count_pkg::Incr)
  ) u_prim_count_ctr_drbg (
    .clk_i,
    .rst_ni,
    .clr_i    (!enable_i),
    .set_i    (v_ctr_load),
    .set_cnt_i(core_data.v[CtrLen-1:0]),
    .incr_en_i(v_ctr_inc),
    .decr_en_i(1'b0),
    .step_i   (CtrLen'(1)),
    .commit_i (1'b1),
    .cnt_o             (v_ctr),
    .cnt_after_commit_o(),
    .err_o             (ctr_err_o)
  );
  
  assign v_ctr_sized = {core_data.v[BlkLen-1:CtrLen], v_ctr};
  
  
  
  assign block_encrypt_req_data_o = '{
    key: core_data.key,
    v:   v_ctr_sized
  };
  
  
  
  
  
  assign concat_ctr_done = (concat_ctr_q >= NumBlkPerUpd);
  
  assign concat_key_v = csrng_key_v_t'(concat_key_v_q);
  always_comb begin
    concat_ctr_d   = concat_ctr_q;
    concat_key_v_d = concat_key_v_q;
    if (!enable_i || concat_ctr_done) begin
      concat_ctr_d   = '0;
      concat_key_v_d = '0;
    end else if (concat_ctr_inc) begin
      concat_ctr_d = concat_ctr_q + 1;
      
      concat_key_v_d[(NumBlkPerUpd - 1 - concat_ctr_q) * BlkLen +: BlkLen]
        = block_encrypt_rsp_data_i;
    end
  end
  
  
  
  always_comb begin
    state_d      = state_q;
    gen_subcmd_d = gen_subcmd_q;
    
    req_rdy_o  = 1'b0;
    rsp_vld_o  = 1'b0;
    bits_vld_o = 1'b0;
    state_db_wr_o = 1'b0;
    block_encrypt_req_vld_o = 1'b0;
    block_encrypt_rsp_rdy_o = 1'b0;
    
    v_ctr_load = 1'b0;
    v_ctr_inc  = 1'b0;
    concat_ctr_inc = 1'b0;
    
    sm_err_o = 1'b0;
    unique case (state_q)
      Idle: begin
        if (enable_i && req_vld_i) begin
          unique case (core_data.cmd)
            UNI: begin
              
              req_rdy_o = 1'b1;
              rsp_vld_o = 1'b1;
              state_db_wr_o = 1'b1;
            end
            INS, RES, UPD: begin
              
              v_ctr_load = 1'b1;
              state_d = CtrInc;
            end
            GEN: begin
              v_ctr_load = 1'b1;
              
              
              
              
              if (core_data.pdata != '0) begin
                gen_subcmd_d = UPD_BEGIN;
              end else begin
                gen_subcmd_d = GEN_LOOP;
              end
              state_d = CtrInc;
            end
            default: begin
              
              state_d = Error;
            end
          endcase
        end else begin
          
          
          block_encrypt_rsp_rdy_o = 1'b1;
        end
      end
      ReqSend: begin
        
        block_encrypt_req_vld_o = 1'b1;
        if (block_encrypt_req_rdy_i) begin
          state_d = RspWait;
        end
      end
      RspWait: begin
        block_encrypt_rsp_rdy_o = 1'b1;
        if (block_encrypt_rsp_vld_i) begin
          
          
          if ((core_data.cmd == GEN) && (gen_subcmd_q == GEN_LOOP)) begin
            bits_vld_o = 1'b1;
          end else begin
            v_ctr_inc = 1'b1;
            concat_ctr_inc = 1'b1;
          end
          
          if (core_data.cmd == GEN) begin
            state_d = HndshkGen;
          end else begin
            state_d = Hndshk;
          end
        end
      end
      Hndshk: begin
        if (concat_ctr_done) begin
          
          req_rdy_o = 1'b1;
          rsp_vld_o = 1'b1;
          state_db_wr_o = 1'b1;
          state_d = Idle;
        end else begin
          
          state_d = ReqSend;
        end
      end
      HndshkGen: begin
        unique case (gen_subcmd_q)
          UPD_BEGIN: begin
            if (concat_ctr_done) begin
              
              
              state_db_wr_o = 1'b1;
              gen_subcmd_d = GEN_LOOP;
              state_d = HndshkLoad;
            end else begin
              state_d = ReqSend;
            end
          end
          GEN_LOOP: begin
            if (req_glast_i) begin
              
              v_ctr_inc = 1'b1;
              gen_subcmd_d = UPD_FINAL;
              state_d = ReqSend;
            end else begin
              
              req_rdy_o = 1'b1;
              rsp_vld_o = 1'b1;
              state_db_wr_o = 1'b1;
              state_d = Idle;
            end
          end
          UPD_FINAL: begin
            if (concat_ctr_done) begin
              
              req_rdy_o = 1'b1;
              rsp_vld_o = 1'b1;
              state_db_wr_o = 1'b1;
              state_d = Idle;
            end else begin
              
              state_d = ReqSend;
            end
          end
          default: begin
            
            state_d = Error;
          end
        endcase
      end
      HndshkLoad: begin
        
        v_ctr_load = 1'b1;
        state_d = CtrInc;
      end
      CtrInc: begin
        
        v_ctr_inc = 1'b1;
        state_d = ReqSend;
      end
      Error: begin
        sm_err_o = 1'b1;
      end
      default: begin
        state_d = Error;
        sm_err_o = 1'b1;
      end
    endcase
    
    
    if (!enable_i && (state_q == RspWait)) begin
      
      
      
      if (block_encrypt_rsp_vld_i) begin
        state_d = Idle;
      end
    end else if (!(state_q inside {Idle, Error}) && (state_d != Error)) begin
      
      if (!enable_i) begin
        state_d = Idle;
      end
    end
  end
  
  
  
  
  assign rsp_sts_o = (core_data.cmd == INV) ? CMD_STS_INVALID_ACMD : CMD_STS_SUCCESS;
  always_comb begin
    
    rsp_data_o = core_data;
    
    
    if (core_data.cmd inside {INS, RES, UPD}) begin
      rsp_data_o.key = concat_key_v.key ^ core_data.pdata[BlkLen +: KeyLen];
      rsp_data_o.v   = concat_key_v.v   ^ core_data.pdata[BlkLen-1:0];
    end else if (core_data.cmd == GEN) begin
      unique case (gen_subcmd_q)
        UPD_BEGIN: begin
          rsp_data_o.key = concat_key_v.key ^ core_data.pdata[BlkLen +: KeyLen];
          rsp_data_o.v   = concat_key_v.v   ^ core_data.pdata[BlkLen-1:0];
        end
        GEN_LOOP: begin
          rsp_data_o.key = core_data.key; 
          rsp_data_o.v   = v_ctr_sized;   
        end
        UPD_FINAL: begin
          rsp_data_o.key = concat_key_v.key ^ generate_adata_q[core_data.inst_id].key;
          rsp_data_o.v   = concat_key_v.v   ^ generate_adata_q[core_data.inst_id].v;
          
          rsp_data_o.rs_ctr = core_data.rs_ctr + 1;
        end
        default:  ;
      endcase
    end
  end
  
  assign bits_data_o = block_encrypt_rsp_data_i;
  assign bits_fips_o = core_data.fips;
  
  
  
  
  `ASSERT_INIT(CsrngCtrLenLessBlkLen, CtrLen < BlkLen)
  
  `ASSERT(CsrngCtrDrbgSmErrorStStable_A, state_q == Error |=> $stable(state_q))
  
  `ASSERT(CsrngCtrDrbgSmErrorOutput_A, !(state_q inside
          {Idle, CtrInc, ReqSend, RspWait, Hndshk, HndshkGen, HndshkLoad})
          |-> sm_err_o)
endmodule

`ifndef PRIM_ASSERT_SV
`define PRIM_ASSERT_SV
`define ASSERT_DEFAULT_CLK clk_i
`define ASSERT_DEFAULT_RST !rst_ni
`define PRIM_STRINGIFY(__x) `"__x`"
`define ASSERT_ERROR(__name)                                                             \
`ifdef UVM                                                                               \
  uvm_pkg::uvm_report_error("ASSERT FAILED", `PRIM_STRINGIFY(__name), uvm_pkg::UVM_NONE, \
                            `__FILE__, `__LINE__, "", 1);                                \
`else                                                                                    \
  $error("%0t: (%0s:%0d) [%m] [ASSERT FAILED] %0s", $time, `__FILE__, `__LINE__,         \
         `PRIM_STRINGIFY(__name));                                                       \
`endif
`define ASSERT_STATIC_LINT_ERROR(__name, __prop)     \
  localparam int __name = (__prop) ? 1 : 2;          \
  always_comb begin                                  \
    logic unused_assert_static_lint_error;           \
    unused_assert_static_lint_error = __name'(1'b1); \
  end
`define ASSERT_STATIC_IN_PACKAGE(__name, __prop)              \
  function automatic bit assert_static_in_package_``__name(); \
    bit unused_bit [((__prop) ? 1 : -1)];                     \
    unused_bit = '{default: 1'b0};                            \
    return unused_bit[0];                                     \
  endfunction
`ifdef VERILATOR
 `include "prim_assert_dummy_macros.svh"`elsif SYNTHESIS
 `include "prim_assert_dummy_macros.svh"`elsif YOSYS
 `include "prim_assert_yosys_macros.svh"
 `define INC_ASSERT`else
 
`define ASSERT_I(__name, __prop) \
  __name: assert (__prop)        \
    else begin                   \
      `ASSERT_ERROR(__name)      \
    end
`define ASSERT_INIT(__name, __prop)                                                  \
`ifdef FPV_ON                                                                        \
  if (!(__prop)) $fatal(2, "Fatal static assertion [%s]: (%s) is not true.",         \
                        (__name), (__prop));                                         \
`else                                                                                \
  initial begin                                                                      \
    __name: assert (__prop)                                                          \
      else begin                                                                     \
        `ASSERT_ERROR(__name)                                                        \
      end                                                                            \
  end                                                                                \
`endif
`define ASSERT_INIT_NET(__name, __prop)                                                   \
  initial begin                                                                      \
    
    
    
    #1ps;                                                                            \
    __name: assert (__prop)                                                          \
      else begin                                                                     \
        `ASSERT_ERROR(__name)                                                        \
      end                                                                            \
  end                                                                                \
`define ASSERT_FINAL(__name, __prop)                                         \
`ifndef FPV_ON                                                               \
  final begin                                                                \
    __name: assert (__prop || $test$plusargs("disable_assert_final_checks")) \
      else begin                                                             \
        `ASSERT_ERROR(__name)                                                \
      end                                                                    \
  end                                                                        \
`endif
`define ASSERT_AT_RESET(__name, __prop, __rst = `ASSERT_DEFAULT_RST)          \
  
  
  
  
  
  
  
  
  
  
`ifndef FPV_ON                                                                \
  __name: assert property (@(posedge __rst) $isunknown(__rst) || (__prop))    \
`else                                                                         \
  __name: assert property (@(posedge __rst) (__prop))                         \
`endif                                                                        \
    else begin                                                                \
      `ASSERT_ERROR(__name)                                                   \
    end
`define ASSERT_AT_RESET_AND_FINAL(__name, __prop, __rst = `ASSERT_DEFAULT_RST) \
    `ASSERT_AT_RESET(AtReset_``__name``, __prop, __rst)                        \
    `ASSERT_FINAL(Final_``__name``, __prop)
`define ASSERT(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  __name: assert property (@(posedge __clk) disable iff ((__rst) !== '0) (__prop))       \
    else begin                                                                           \
      `ASSERT_ERROR(__name)                                                              \
    end
`define ASSERT_NEVER(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  __name: assert property (@(posedge __clk) disable iff ((__rst) !== '0) not (__prop))         \
    else begin                                                                                 \
      `ASSERT_ERROR(__name)                                                                    \
    end
`define ASSERT_KNOWN(__name, __sig, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
`ifndef FPV_ON                                                                                \
  `ASSERT(__name, !$isunknown(__sig), __clk, __rst)                                           \
`endif
`define COVER(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  __name: cover property (@(posedge __clk) disable iff ((__rst) !== '0) (__prop));
`define ASSUME(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  __name: assume property (@(posedge __clk) disable iff ((__rst) !== '0) (__prop))       \
    else begin                                                                           \
      `ASSERT_ERROR(__name)                                                              \
    end
`define ASSUME_I(__name, __prop) \
  __name: assume (__prop)        \
    else begin                   \
      `ASSERT_ERROR(__name)      \
    end
 `define INC_ASSERT
`endif
`define ASSERT_PULSE(__name, __sig, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  `ASSERT(__name, $rose(__sig) |=> !(__sig), __clk, __rst)
`define ASSERT_IF(__name, __prop, __enable, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  `ASSERT(__name, (__enable) |-> (__prop), __clk, __rst)
`define ASSERT_KNOWN_IF(__name, __sig, __enable, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
`ifndef FPV_ON                                                                                             \
  `ASSERT_KNOWN(__name``KnownEnable, __enable, __clk, __rst)                                               \
  `ASSERT_IF(__name, !$isunknown(__sig), __enable, __clk, __rst)                                           \
`endif
`define ASSUME_FPV(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
`ifdef FPV_ON                                                                                \
   `ASSUME(__name, __prop, __clk, __rst)                                                     \
`endif
`define ASSUME_I_FPV(__name, __prop) \
`ifdef FPV_ON                        \
   `ASSUME_I(__name, __prop)         \
`endif
`define COVER_FPV(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
`ifdef FPV_ON                                                                               \
   `COVER(__name, __prop, __clk, __rst)                                                     \
`endif
`define ASSERT_FPV_LINEAR_FSM(__name, __state, __type, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  `ifdef INC_ASSERT                                                                                              \
     bit __name``_cond;                                                                                          \
     always_ff @(posedge __clk or posedge __rst) begin                                                           \
       if (__rst) begin                                                                                          \
         __name``_cond <= 0;                                                                                     \
       end else begin                                                                                            \
         __name``_cond <= 1;                                                                                     \
       end                                                                                                       \
     end                                                                                                         \
     property __name``_p;                                                                                        \
       __type initial_state;                                                                                     \
       (!$stable(__state) & __name``_cond, initial_state = $past(__state)) |->                                   \
           (__state != initial_state) until !(__name``_cond);                                                    \
     endproperty                                                                                                 \
   `ASSERT(__name, __name``_p, __clk, 0)                                                                         \
  `endif
`ifndef PRIM_ASSERT_SEC_CM_SVH
`define PRIM_ASSERT_SEC_CM_SVH
`define _SEC_CM_ALERT_MAX_CYC 30
`define ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, ERR_NAME_, CLK_, RST_) \
  `ASSERT(FpvSecCm``NAME_``,                                                                    \
          $rose(HIER_.ERR_NAME_) && !(GATE_) |-> ##[0:MAX_CYCLES_] (ERR_),                      \
          CLK_, RST_)                                                                           \
  `ifdef INC_ASSERT                                                                             \
    assign HIER_.unused_assert_connected = 1'b1;                                                \
  `endif
`define ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, ERR_NAME_)    \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, (ALERT_.alert_p), GATE_, MAX_CYCLES_, ERR_NAME_, \
                            `ASSERT_DEFAULT_CLK, `ASSERT_DEFAULT_RST)                      \
  `ASSUME_FPV(``NAME_``TriggerAfterAlertInit_S,                                            \
              $stable(rst_ni) == 0 |-> HIER_.ERR_NAME_ == 0 [*10])
`define ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_IN_, GATE_, MAX_CYCLES_, ERR_NAME_) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ALERT_IN_, GATE_, MAX_CYCLES_, ERR_NAME_,           \
                            `ASSERT_DEFAULT_CLK, `ASSERT_DEFAULT_RST)
`define ASSERT_PRIM_COUNT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_DOUBLE_LFSR_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_FSM_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, unused_err_o)
`define ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_REG_WE_ONEHOT_ERROR_TRIGGER_ALERT(NAME_, REG_TOP_HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ALERT(NAME_, \
    REG_TOP_HIER_.u_prim_reg_we_check.u_prim_onehot_check, ALERT_, GATE_, MAX_CYCLES_)
`define ASSERT_PRIM_FIFO_SYNC_SINGLETON_ERROR_TRIGGER_ALERT(NAME, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_COUNT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_DOUBLE_LFSR_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_FSM_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, unused_err_o)
`define ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_REG_WE_ONEHOT_ERROR_TRIGGER_ALERT_IN(NAME_, REG_TOP_HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ALERT_IN(NAME_, \
    REG_TOP_HIER_.u_prim_reg_we_check.u_prim_onehot_check, ALERT_, GATE_, MAX_CYCLES_)
`define ASSERT_PRIM_FIFO_SYNC_SINGLETON_ERROR_TRIGGER_ALERT_IN(NAME, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_FSM_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = 2, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, unused_err_o, CLK_, RST_)
`define ASSERT_PRIM_COUNT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = 2, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, err_o, CLK_, RST_)
`define ASSERT_PRIM_DOUBLE_LFSR_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = 2, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, err_o, CLK_, RST_)
`define ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, err_o, CLK_, RST_)
`define ASSERT_PRIM_REG_WE_ONEHOT_ERROR_TRIGGER_ERR(NAME_, REG_TOP_HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ERR(NAME_, \
    REG_TOP_HIER_.u_prim_reg_we_check.u_prim_onehot_check, ERR_, GATE_, MAX_CYCLES_, CLK_, RST_)
`endif 
`ifndef PRIM_FLOP_MACROS_SV
`define PRIM_FLOP_MACROS_SV
`define PRIM_FLOP_CLK clk_i
`define PRIM_FLOP_RST rst_ni
`define PRIM_FLOP_RESVAL '0
`define PRIM_FLOP_A(__d, __q, __resval = `PRIM_FLOP_RESVAL, __clk = `PRIM_FLOP_CLK, __rst_n = `PRIM_FLOP_RST) \
  always_ff @(posedge __clk or negedge __rst_n) begin \
    if (!__rst_n) begin                               \
      __q <= __resval;                                \
    end else begin                                    \
      __q <= __d;                                     \
    end                                               \
  end
`define PRIM_FLOP_SPARSE_FSM(__name, __d, __q, __type, __resval = `PRIM_FLOP_RESVAL, __clk = `PRIM_FLOP_CLK, __rst_n = `PRIM_FLOP_RST, __alert_trigger_sva_en = 1) \
  `ifdef SIMULATION                                   \
    prim_sparse_fsm_flop #(                           \
      .StateEnumT(__type),                            \
      .Width($bits(__type)),                          \
      .ResetValue($bits(__type)'(__resval)),          \
      .EnableAlertTriggerSVA(__alert_trigger_sva_en), \
      .CustomForceName(`PRIM_STRINGIFY(__q))          \
    ) __name (                                        \
      .clk_i   ( __clk   ),                           \
      .rst_ni  ( __rst_n ),                           \
      .state_i ( __d     ),                           \
      .state_o (         )                            \
    );                                                \
    `PRIM_FLOP_A(__d, __q, __resval, __clk, __rst_n)  \
    `ASSERT(``__name``_A, __q === ``__name``.state_o) \
  `else                                               \
    prim_sparse_fsm_flop #(                           \
      .StateEnumT(__type),                            \
      .Width($bits(__type)),                          \
      .ResetValue($bits(__type)'(__resval)),          \
      .EnableAlertTriggerSVA(__alert_trigger_sva_en)  \
    ) __name (                                        \
      .clk_i   ( __clk   ),                           \
      .rst_ni  ( __rst_n ),                           \
      .state_i ( __d     ),                           \
      .state_o ( __q     )                            \
    );                                                \
  `endif
`endif 
`endif 
module csrng_main_sm import csrng_pkg::*; (
  input  logic                        clk_i,
  input  logic                        rst_ni,
  input  logic                        enable_i,
  input  logic                        acmd_avail_i,
  output logic                        acmd_accept_o,
  input  acmd_e                       acmd_i,
  input  logic                        acmd_eop_i,
  input  logic                        flag0_i,
  output logic                        cmd_entropy_req_o,
  input  logic                        cmd_entropy_avail_i,
  output logic                        cmd_vld_o,
  input  logic                        cmd_rdy_i,
  output logic                        clr_adata_packer_o,
  input  logic                        cmd_complete_i,
  input  logic                        local_escalate_i,
  output logic [MainSmStateWidth-1:0] main_sm_state_o,
  output logic                        main_sm_err_o
);
  
  main_sm_state_e state_d, state_q;
  `PRIM_FLOP_SPARSE_FSM(u_state_regs, state_d, state_q, main_sm_state_e, MainSmIdle)
  assign main_sm_state_o = {state_q};
  always_comb begin
    state_d            = state_q;
    acmd_accept_o      = 1'b0;
    cmd_entropy_req_o  = 1'b0;
    cmd_vld_o          = 1'b0;
    clr_adata_packer_o = 1'b0;
    main_sm_err_o      = 1'b0;
    if (state_q == MainSmError) begin
      
      main_sm_err_o = 1'b1;
    end else if (local_escalate_i) begin
      
      state_d = MainSmError;
    end else if (!enable_i && state_q inside {MainSmIdle, MainSmParseCmd, MainSmEntropyReq,
                                              MainSmCmdPrep, MainSmCmdVld,
                                              MainSmClrAData, MainSmCmdCompWait}) begin
      
      state_d = MainSmIdle;
    end else begin
      
      unique case (state_q)
        MainSmIdle: begin
          
          if (acmd_avail_i) begin
            acmd_accept_o = 1'b1;
            state_d = MainSmParseCmd;
          end
        end
        MainSmParseCmd: begin
          if (acmd_eop_i) begin
            unique case (acmd_i)
              INS, RES:      state_d = MainSmEntropyReq; 
              GEN, UPD, UNI: state_d = MainSmCmdPrep;    
              default:       state_d = MainSmIdle;       
            endcase
          end
        end
        MainSmEntropyReq: begin
          if (flag0_i) begin
            
            state_d = MainSmCmdVld;
          end else begin
            
            cmd_entropy_req_o = 1'b1;
            if (cmd_entropy_avail_i) begin
              state_d = MainSmCmdVld;
            end
          end
        end
        MainSmCmdPrep: begin
          
          state_d = MainSmCmdVld;
        end
        MainSmCmdVld: begin
          cmd_vld_o = 1'b1;
          if (cmd_rdy_i) begin
            if (cmd_complete_i) begin
              clr_adata_packer_o = 1'b1;
              state_d = MainSmIdle;
            end else begin
              state_d = MainSmClrAData;
            end
          end
        end
        MainSmClrAData: begin
          clr_adata_packer_o = 1'b1;
          if (cmd_complete_i) begin
            state_d = MainSmIdle;
          end else begin
            state_d = MainSmCmdCompWait;
          end
        end
        MainSmCmdCompWait: begin
          if (cmd_complete_i) begin
            state_d = MainSmIdle;
          end
        end
        
        default: begin
          state_d = MainSmError;
          main_sm_err_o = 1'b1;
        end
      endcase
    end
  end
  
  
  `ASSERT(CsrngMainErrorStStable_A, state_q == MainSmError |=> $stable(state_q))
  
  `ASSERT(CsrngMainErrorOutput_A,   state_q == MainSmError |-> main_sm_err_o)
endmodule

package csrng_pkg;
  parameter int unsigned NumAppsLg = $clog2(csrng_reg_pkg::NumApps);
  
  
  
  
  parameter int unsigned BlkLen = 128;
  
  parameter int unsigned KeyLen = 256;
  
  parameter int unsigned SeedLen = BlkLen + KeyLen;
  
  
  parameter int unsigned CtrLen = 32;
  parameter int unsigned RsCtrWidth = 32;
  
  parameter int unsigned GenBitsCtrWidth = 12;
  
  parameter int unsigned CmdWidth = 3;
  parameter int unsigned InstIdWidth = 4;
  
  parameter int unsigned CmdBusWidth = 32;
  
  parameter int unsigned CmdMaxClen = 12;
  parameter int unsigned CmdFifoDepth = 2;
  parameter int unsigned CmdFifoDepthLg = $clog2(CmdFifoDepth);
  parameter int unsigned GENBITS_BUS_WIDTH = BlkLen;
  parameter int unsigned FIPS_GENBITS_BUS_WIDTH = entropy_src_pkg::FIPS_BUS_WIDTH +
                         GENBITS_BUS_WIDTH;
  
  
  
  typedef struct packed {
    logic                   csrng_req_valid;
    logic [CmdBusWidth-1:0] csrng_req_bus;
    logic                   genbits_ready;
  } csrng_req_t;
  parameter int unsigned CmdStatusWidth = 3;
  typedef enum logic [CmdStatusWidth-1:0] {
    CMD_STS_SUCCESS              = 'h0,
    CMD_STS_INVALID_ACMD         = 'h1,
    CMD_STS_INVALID_GEN_CMD      = 'h2,
    CMD_STS_INVALID_CMD_SEQ      = 'h3,
    CMD_STS_RESEED_CNT_EXCEEDED  = 'h4,
    CMD_STS_UNDRIVEN             = 'z
  } csrng_cmd_sts_e;
  typedef struct packed {
    logic                         csrng_req_ready;
    logic                         csrng_rsp_ack;
    csrng_cmd_sts_e               csrng_rsp_sts;
    logic                         genbits_valid;
    logic                         genbits_fips;
    logic [GENBITS_BUS_WIDTH-1:0] genbits_bus;
  } csrng_rsp_t;
  parameter csrng_req_t CSRNG_REQ_DEFAULT = '{default: '0};
  parameter csrng_rsp_t CSRNG_RSP_DEFAULT = '0;
  typedef enum logic [CmdWidth-1:0] {
    INV  = 3'h0,
    INS  = 3'h1,
    RES  = 3'h2,
    GEN  = 3'h3,
    UPD  = 3'h4,
    UNI  = 3'h5
  } acmd_e;
  typedef struct packed {
    logic  [7:0] resv;
    logic [11:0] glen;
    logic  [3:0] flag0;
    logic  [3:0] clen;
    logic        gap; 
    acmd_e       acmd;
  } csrng_cmd_t;
  
  
  
  typedef struct packed {
    logic                   fips;
    logic  [RsCtrWidth-1:0] rs_ctr;
    logic     [SeedLen-1:0] pdata;
    logic   [NumAppsLg-1:0] inst_id;
    acmd_e                  cmd;
    logic      [KeyLen-1:0] key;
    logic      [BlkLen-1:0] v;
  } csrng_core_data_t;
  typedef struct packed {
    logic [KeyLen-1:0] key;
    logic [BlkLen-1:0] v;
  } csrng_key_v_t;
  
  
  typedef struct packed {
    logic                  fips;
    logic                  inst_state;
    logic     [KeyLen-1:0] key;
    logic     [BlkLen-1:0] v;
    logic [RsCtrWidth-1:0] rs_ctr;
  } csrng_state_t;
  parameter int unsigned StateWidth    = $bits(csrng_state_t);
  parameter int unsigned MainSmStateWidth = 6;
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  typedef enum logic [MainSmStateWidth-1:0] {
    MainSmIdle        = 6'b110111, 
    MainSmParseCmd    = 6'b011101, 
    MainSmEntropyReq  = 6'b001110, 
    MainSmCmdPrep     = 6'b000011, 
    MainSmCmdVld      = 6'b010000, 
    MainSmClrAData    = 6'b111010, 
    MainSmCmdCompWait = 6'b100100, 
    MainSmError       = 6'b101001  
  } main_sm_state_e;
  parameter int CsKeymgrDivWidth = 384;
  typedef logic [CsKeymgrDivWidth-1:0] cs_keymgr_div_t;
endpackage : csrng_pkg

package csrng_reg_pkg;
  
  parameter int NumApps = 3;
  parameter int NumAlerts = 2;
  
  parameter int BlockAw = 7;
  
  parameter int NumRegs = 24;
  
