    .rst_ni  (rst_ni),
    
    .we     (1'b0),
    .wd     ('0),
    
    .de     (hw2reg.main_sm_state.de),
    .d      (hw2reg.main_sm_state.d),
    
    .qe     (),
    .q      (),
    .ds     (),
    
    .qs     (main_sm_state_qs)
